INSERT INTO `master_questions` VALUES (1,'Did you smoke?',1,'smoke','yesno',NULL,NULL),(2,'Did you drink any alcohol?',2,'drink','yesno',NULL,NULL),(3,'How frequently did you feel stressed?',3,'anxious','time',NULL,NULL),(4,'How would you describe your eating habits and diet quality?',4,'dietaryquality','level',NULL,'{\"max\": 10, \"min\": 1, \"Fair\": [4, 5], \"Good\": [6, 7], \"Poor\": [1, 2, 3], \"VeryGood\": [8, 9], \"Excellent\": [10]}'),(5,'Did you consume any food high in salt or is highly processed (e.g. fish ball noodles, lor mee, nasi biryani, instant noodles, luncheon meat, Chinese sausage/lap cheong, fish & chips)?',5,'processedfood','yesno',NULL,NULL),(6,'In a typical day, how many servings of fruit and vegetables did you eat?',6,'fruitandvegetables','level',NULL,'{\"max\": 10, \"min\": 0, \"Fair\": [1, 2], \"Good\": [3, 4], \"Poor\": [0], \"VeryGood\": [5, 6], \"Excellent\": [7, 8, 9, 10]}'),(7,'How often did you include wholegrains (e.g. brown rice, oats, wholemeal bread) in your diet?',7,'diet','time',NULL,NULL),(8,'How often did you opt for less or no sugar in your food and drinks?',8,'nosugar','time',NULL,NULL),(9,'How often did you consume unhealthy oils and fats (e.g. meats/poultry especially with skin, lard, ghee, butter, whole milk, coconut oil, palm oil, fried foods, cakes, cookies, pastries)?',9,'oils_and_fats','time',NULL,NULL),(10,'Fill latest readings and date of tests/measures that were done within past 2 weeks.',10,'readings','form','[{\"type\": \"last_date_of_measures\", \"index\": 1, \"value\": \"Last date of test/measures\", \"answer_type\": \"date\"}, {\"type\": \"height\", \"index\": 2, \"range\": {\"step\": 1, \"maxHeight\": 250, \"minHeight\": 50}, \"value\": \"Height\", \"defaultUnit\": \"cm\", \"converterMap\": [{\"id\": 0, \"title\": \"cm\"}, {\"id\": 1, \"title\": \"ft\"}], \"dropdownFields\": [\"cm\", \"ft\"]}, {\"type\": \"weight\", \"index\": 3, \"range\": {\"step\": 1, \"maxHeight\": 200, \"minHeight\": 50}, \"value\": \"Weight\", \"defaultUnit\": \"kg\", \"converterMap\": [{\"id\": 0, \"title\": \"kg\"}, {\"id\": 1, \"title\": \"lbs\"}], \"dropdownFields\": [\"kg\", \"lbs\"]}, {\"type\": \"BMI\", \"unit\": \"cm\", \"index\": 4, \"value\": \"BMI\", \"answer_type\": \"textinput\"}, {\"type\": \"waist_circumference\", \"index\": 5, \"range\": {\"step\": 1, \"maxHeight\": 300, \"minHeight\": 50}, \"value\": \"Waist Circumference\", \"defaultUnit\": \"cm\", \"converterMap\": [{\"id\": 0, \"title\": \"cm\"}, {\"id\": 1, \"title\": \"in\"}], \"dropdownFields\": [\"cm\", \"in\"]}, {\"type\": \"hba1c\", \"index\": 6, \"range\": {\"step\": 1, \"maxHeight\": 200, \"minHeight\": 30}, \"value\": \"HbA1c\", \"defaultUnit\": \"%\", \"converterMap\": [{\"id\": 0, \"title\": \"%\"}, {\"id\": 1, \"title\": \"mmol/mol\"}], \"dropdownFields\": [\"%\", \"mmol/mol\"]}, {\"type\": \"blood_glucose\", \"index\": 7, \"range\": {\"step\": 1, \"maxHeight\": 400, \"minHeight\": 60}, \"value\": \"Fasting Blood Glucose\", \"defaultUnit\": \"mmol/L\", \"converterMap\": [{\"id\": 0, \"title\": \"mg/dl\"}, {\"id\": 1, \"title\": \"mmol/L\"}], \"dropdownFields\": [\"mg/dl\", \"mmol/L\"]}, {\"type\": \"total_cholesterol\", \"index\": 8, \"range\": {\"step\": 1, \"maxHeight\": 200, \"minHeight\": 30}, \"value\": \"Total Cholesterol\", \"defaultUnit\": \"mmol/L\", \"converterMap\": [{\"id\": 0, \"title\": \"mg/dl\"}, {\"id\": 1, \"title\": \"mmol/L\"}], \"dropdownFields\": [\"mg/dl\", \"mmol/L\"]}, {\"type\": \"HDL\", \"index\": 9, \"range\": {\"step\": 1, \"maxHeight\": 200, \"minHeight\": 30}, \"value\": \"HDL Cholesterol\", \"defaultUnit\": \"mmol/L\", \"converterMap\": [{\"id\": 0, \"title\": \"mg/dl\"}, {\"id\": 1, \"title\": \"mmol/L\"}], \"dropdownFields\": [\"mg/dl\", \"mmol/L\"]}, {\"type\": \"LDL\", \"index\": 10, \"range\": {\"step\": 1, \"maxHeight\": 200, \"minHeight\": 30}, \"value\": \"LDL Cholesterol\", \"defaultUnit\": \"mmol/L\", \"converterMap\": [{\"id\": 0, \"title\": \"mg/dl\"}, {\"id\": 1, \"title\": \"mmol/L\"}], \"dropdownFields\": [\"mg/dl\", \"mmol/L\"]}, {\"type\": \"triglycerides\", \"index\": 11, \"range\": {\"step\": 1, \"maxHeight\": 200, \"minHeight\": 30}, \"value\": \"Triglycerides\", \"defaultUnit\": \"mmol/L\", \"converterMap\": [{\"id\": 0, \"title\": \"mg/dl\"}, {\"id\": 1, \"title\": \"mmol/L\"}], \"dropdownFields\": [\"mg/dl\", \"mmol/L\"]}, {\"type\": \"units\", \"parameters\": {\"HDL\": \"mmol/L\", \"LDL\": \"mmol/L\", \"hba1c\": \"%\", \"height\": \"cm\", \"weight\": \"kg\", \"blood_glucose\": \"mmol/L\", \"triglycerides\": \"mmol/L\", \"total_cholesterol\": \"mmol/L\", \"waist_circumference\": \"cm\"}}]',NULL);
