CREATE TABLE `notifications_scheduled` (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` text NOT NULL,
  `message` text NOT NULL,
  `isSent` enum('pending','success','failed') NOT NULL DEFAULT 'pending',
  `createdAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updatedAt` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `isDeleted` tinyint NOT NULL DEFAULT '0',
  `userId` int NOT NULL,
  `isEmail` tinyint NOT NULL DEFAULT '0',
  `isQuiz` tinyint NOT NULL,
  `scheduledDate` bigint NOT NULL,
  `sentCount` int DEFAULT NULL,
  `isRead` tinyint NOT NULL DEFAULT '0',
  `quizUserAnswer` text,
  `quizCorrectAnswer` text,
  `type` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `IDX_fbee76c5615cdc8f5aa3434f25` (`userId`,`type`,`createdAt`),
  KEY `IDX_4ba2ed9e47f16a9c9564787566` (`userId`,`isSent`,`type`,`scheduledDate`),
  KEY `IDX_02211d6d963f385bbbcc79bbac` (`userId`,`isSent`,`type`),
  KEY `IDX_87fa67884530ce54fca7d2d37c` (`userId`,`isDeleted`,`type`)
) ENGINE=InnoDB AUTO_INCREMENT=68698 DEFAULT CHARSET=utf8mb3;
/*!40101 SET character_set_client = @saved_cs_client */;

