INSERT INTO `notifications_scheduled` VALUES (68367,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1756609200,NULL,0,NULL,NULL,'push'),(68368,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Products high in fibre are also high in wholegrains.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,1,1757214000,NULL,0,NULL,'\n         <p><strong >Answer: FALSE</strong> </br>Just because a product is high in fibre does not necessarily mean that it is wholegrain.\n      Food enriched or added with wheat or bran may be high in fibre but they are not wholegrain unless wholewheat or other wholegrains are used in the product.</p>\n    ','push'),(68369,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Brown bread has wholegrains.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,1,1757818800,NULL,0,NULL,'\n    <p><strong >Answer: FALSE</strong> <br/>\n      Don\'t judge a grain by its colour. Just because the bread is brown doesn\'t mean it is made of wholegrains.\n      Some bread or crackers may be brown because ​molasses or caramel colouring may have been added.\n      Don\'t forget that many wholegrain products such as cereals are light in colour.</p>\n\n      <p >Also, wholegrain food are not always dry and gritty.\n      You will be pleasantly surprised that some wholegrains are light and flaky like cereal grains while some may be dense with an enjoyable nutty flavour.</p>\n    ','push'),(68370,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span>Unfortunately, the ingredient list and the nutrition information panel (NIP) will not tell you the amount of wholegrains present in the food. So how?</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the word \"whole\"</span><br><span>The ingredient list will show the wholegrain as an ingredient e.g. wholewheat flour or whole oats. Look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on a product to ensure it is a wholegrain product. </span></p><p><span>The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>But there are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1758423600,NULL,0,NULL,NULL,'push'),(68371,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the Healthier Choice Symbol</span><br><span>Products carrying the \"Higher in Wholegrains\" symbol contain more wholegrains compared to similar products from the same food category.</span><br><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></p><span>When you see this symbol, it means that the:</span><ul style=\"margin-top:0\"><li>Bread and breakfast cereals contains at least 25% wholegrains.</li><li>Brown rice or oats contains 100% wholegrains.</li><li>Vermicelli (bee hoon) contains at least 80% wholegrains.</li><li>Biscuits contains at least 30% wholegrains.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1759028400,NULL,0,NULL,NULL,'push'),(68372,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1759633200,NULL,0,NULL,NULL,'push'),(68373,'How to limit sugar when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Both HCS and Nutri-Grade Mark are the same.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,1,1760238000,NULL,0,NULL,'\n  <p><strong >Answer: FALSE</strong> <br />\n      The Nutri-Grade mark is a labelling scheme for beverages based on their sugar and saturated fat content.</br>Beverages which are Nutri-Grade “C” or “D” will be labelled with a Nutri-Grade mark, while labelling of beverages graded “A” or “B” is optional.</br>When having beverages, choose HCS, Nutri-Grade “A”/”B” beverages or simply water to control your sugar and saturated fat intake.</p>\n\n      <span style=\"color: #FF98B7;\">Tip:<br />\n  </span>Explore the list of drink options that are lower in sugar and saturated fats at\n      <a  href=\"https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">\n       https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home \n      </a></p>\n    ','push'),(68374,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1760842800,NULL,0,NULL,NULL,'push'),(68375,'How to tell if a food is healthy by reading the label?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Why is it important to read and understand food labels?</span><br><span>Reading food labels is the first step to making sure your kitchen is stocked with healthier food products.</span></p><p><span>The front, back and sides of a packaged product are filled with clues that tell you what the food contains and how much you are eating. These information can guide you in making healthier purchases to cut back on sodium, choose wholegrain products, reduce unhealthy oil and fats, and limit sugar.</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">What happens if we do not read food labels?</span><br><span>Without reading food labels, we might eat more calories than necessary, misjudge portion sizes and unknowingly consume high amounts of sugar, salt and unhealthy fats. We might also accidentally consume allergens or ingredients we are sensitive to, triggering undesired reactions. </span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Not everything has a food label</span><br><span>Fresh produce like fruit and vegetables that have not been peeled, cut or processed, herbs and spices, tea, coffee, flours and alcoholic drinks may not have a food label. </span></p><p><span>Aim to eat at least 2 servings of fruit and 2 servings of vegetables a day. On the other hand, try to limit alcohol intake as excessive alcohol consumption can ruin your health. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1761447600,NULL,0,NULL,NULL,'push'),(68376,'Tips for understanding food labels','<html><head></head><body><p><span>1. Read the ingredients list</span><br><span>2. Check the nutrition information panel</span><br><span>3. Be aware of the calorie count</span><br><span>4. Find out the type of fat, and how much</span><br><span>6. Spot hidden sugar</span><br><span>7. Beware of salt</span><br><span>8. Know your portion size</span></p><p><span>In the coming weeks, I can share more with you how to read and understand food labels.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1762052400,NULL,0,NULL,NULL,'push'),(68377,'Read the ingredients list','<html><head></head><body><p><span>Most packaged foods have an ingredients list on the back or side of the packet. Everything that goes into your food will be listed in weight order from biggest to the smallest. </span></p><p><span>If the first few ingredients you see are cream, butter, fatty meat or cheese, then you know that saturated fat makes up the largest proportion of the product. </span></p><p><span>If you spot sugars (white or brown), syrups or concentrated fruit juice at the top of the ingredients list, then you know that the product you are eyeing is loaded with sugar.</span></p><p><span>Ingredients that appear further down the list are present in the product in small quantities but that does not mean their impact is small. For example, vitamins and minerals are often added to foods like breakfast cereals and dairy in small quantities but can make a positive impact on your diets. </span></p><p><span>Similarly, even small amounts of salt can add up to our maximum of one teaspoon of salt a day.</span></p><p><span style=\"color: #FF98B7; font-style: italic; font-weight: 500;\">Beware:</span><br><span>Manufacturers may use less common names for ingredients such as sodium chloride in place of salt or maltose and fructose for sugars so people may think a certain ingredient is not in the ingredient list.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1762657200,NULL,0,NULL,NULL,'push'),(68378,'Check the nutritional information panel','<html><head></head><body><p>Use the nutrition information panel to find out the amount of nutrients you are getting out of the product.</p><p><strong>Servings per package </strong><br>The number of servings in a single container or packet. There could be more than one serving per package. </p><p><strong>Serving size </strong><br>This measure of a single-serving is defined by the manufacturer and varies from product to product. Be aware that the single serving indicated may be less than what you would typically eat.</p><p>A packet of potato chips may contain 160 calories per 30g serving and contain ten servings. This means if you eat the whole packet, you would have had a whopping 1,600 calories. </p><p><strong>Comparing values</strong><br>The most important ones to look out for are the BIG FOUR: total fat, saturated fat, sugar and salt. These can affect your weight and blood pressure, contributing to your risk of heart disease and stroke. </p><p>But you can also compare other nutrients to make healthier choices, including unsaturated fats (the good kind of fats), wholegrains and fibre.</p><p>When choosing between items look at the ‘per 100g’ or ‘per 100ml’ column as it offers a fairer comparison rather than serving size, which varies between products. </p><p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><br>Focus on the key nutrients that are important to you.<br>If you are on a diet, look at the energy or calorie values. For people with high blood pressure, zoom in on the sodium value or check the saturated fat and cholesterol amounts if you have high cholesterol.</p><p><a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Find out more at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1763262000,NULL,0,NULL,NULL,'push'),(68379,'Be aware of the calorie count ','<html><head></head><body><p><span>Calories (kcal) are a measure of how much energy is in a product. </span></p><p><span>Generally, women need around 1800 calories a day and men need around 2200 calories. But, the exact amounts needed by different persons will vary depending on their age, gender, height, weight and activity level.</span></p><p><span>Constant calorie counting isn\'t necessary but it\'s good to be aware of your calorie intake, especially if you want to maintain a healthy weight or lose a few extra pounds if necessary.</span></p><p><span>One way is to check the caloric content of the products you eat using \"per portion\" information, but do check how the manufacturer\'s portion compares with the portion you actually eat. For example, the manufacturer\'s portion might be two squares of chocolates but the actual amount of chocolates you eat might be much more.</span></p><p><span>Another way is to look for products carrying the Healthier Choice Symbol (HCS) with this tagline, such as crisps/chips where each individually packaged portion is less than or equal to 100 calories. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_100_calories.jpg\" alt=\"Less Than 100\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Products carrying HCS with this tagline are ice cream products that are both lower in sugar compared to similar products in the same food category and less than or equal to 200 calories per portion. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_200_Calories.jpg\" alt=\"Less Than 200\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Choosing your snacks wisely can keep your energy levels up without piling on added calories. </span><br><span>Do you recall seeing this HCS label on the last snack you ate? </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1763866800,NULL,0,NULL,NULL,'push'),(68380,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1764471600,NULL,0,NULL,NULL,'push'),(68381,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1765076400,NULL,0,NULL,NULL,'push'),(68382,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1765681200,NULL,0,NULL,NULL,'push'),(68383,'Look out for \'whole\' in the ingredient list  ','<html><head></head><body><p><span>To identify wholegrain products, look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on the ingredient list. The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>There are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p><p><span>Another way is to look for products carrying the \"Higher in Wholegrains\" Healthier Choice Symbol, which contain more wholegrains compared to similar products from the same food category. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p> <a href=\"https://youtu.be/XmbV3VeDjM4?si=0Z4aQd2Wc-QqhPgp\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Go Wholegrain - Watch Youtube Video</a></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1766286000,NULL,0,NULL,NULL,'push'),(68384,'Know your portion size ','<html><head></head><body><p><span>You can find the amount of nutrition per portion on the nutrition information panel. The portion size is recommended by the manufacturer, and can vary between brands.</span></p><p><span>Be aware that the manufacturer\'s portion size might be smaller than yours, which means that even if a product looks healthy, if you have more than this amount, you may still end up consuming more calories, saturated fat, sugar or salt than you realize.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1766890800,NULL,0,NULL,NULL,'push'),(68385,'Let\'s Recap. ','<html><head></head><body><p>Shopping for healthy groceries allows you to cut back on sodium, find wholegrain products, reduce unhealthy oil and fats and limit sugar. One way is to understand food labels.<br><br>In the coming week, which method would you like to try out?</p><ul style=\"margin-top: 0;\"><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1767495600,NULL,0,NULL,NULL,'push'),(68386,'Hey Tressa, did you manage to try out any of these grocery shopping methods?','<html><head></head><body><ul><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one method.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1767927600,NULL,0,NULL,NULL,'push'),(68387,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #1 Don\'t shop on an empty stomach</span><br><span>It\'s harder to resist buying higher-fat, higher-calorie snack items when you\'re hungry. Shop after you\'ve eaten a good meal. Drink some water or munch on a fruit before you shop.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1768100400,NULL,0,NULL,NULL,'push'),(68388,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Make a shopping list</span><br><span>Make a shopping list to reduce the urge to buy on impulse. Having a well-planned grocery list also saves time and helps you stick to your healthy eating plan.</span></p><span style=\"color: #FF98B7; font-weight: 500; \">Tips:</span><ul style=\" margin-top: 0;\"><li>Buy only what you will use, not because it is on promotion.</li><li>Resist \"buy one get one\" unless it is a staple.</li><li>Use store apps to compare prices.</li><li>Choose house-brands.</li><li>Select items with longer use-by date.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1768705200,NULL,0,NULL,NULL,'push'),(68389,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Go fresh </span><br>Choose fresh or frozen produce and less processed, wholesome foods (e.g. grains, nuts, eggs, herbs and spices) wherever possible.<br><br>Fresh produce are generally better than processed and ready-to-eat foods so that you know exactly what goes into your meal when you cook at home. They are also lower in fat, sugars and additives.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top:0;\"><li>Spend more time in the fresh produce section.</li><li>Limit your time in the aisles that stock snack food/candy and canned/processed foods.</li><li>Stick reminders on your fridge so that perishable fruit and vegetables are not forgotten in your fridge.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1769310000,NULL,0,NULL,NULL,'push'),(68390,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#4 Frozen or fresh </span><br>Frozen fruits and vegetables are flash-frozen to lock in their nutrients immediately after harvest. Fresh or frozen, fruit and vegetables are nutritious and healthier food choices. <br><br>Frozen produce is easy to keep in the freezer for when needed and will keep for far longer than fresh produce, helping to reduce food waste and save money. For out-of-season items, they can be cheaper than fresh produce.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\"margin-top:0\"><li>Buy enough to ensure everyone in your family have sufficient servings.</li><li>Eat a rainbow. Choose fruit and vegetables of different colours to get the maximum nutrients you need.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1769914800,NULL,0,NULL,NULL,'push'),(68391,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#5 Shop in season. Shop local.</span><br><span>Buy fruits and vegetables in season as they peak in flavour and nutrients, and are cheaper.</span></p><p><span>Most of our fruits and vegetables come from Malaysia, China, USA and Australia while local farms produce 12 percent of our leafy vegetables. Shorter time from source to market means fewer nutrients and flavour are lost in transit.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1770519600,NULL,0,NULL,NULL,'push'),(68392,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #6 Check food labels </span><br>If you have to buy processed or packaged foods, look out for the Healthier Choice Symbol (HCS). </p><p>The HCS can be found on the packaging of products such as convenience meals, sauces, drinks, snacks and breakfast cereals. Do you recall seeing the HCS on the items you bought recently? </p><p>Use the HCS to compare similar products so that you can choose the healthiest option. </p><p>You can also use the Nutrition Information Panel (NIP) to find out the amount of calories and nutrients you are getting out of each serving of food. <a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" target=\"_blank\" rel=\"noopener noreferrer\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Learn how to read the NIP at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1771124400,NULL,0,NULL,NULL,'push'),(68393,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#7 To buy organic produce or not</span><br><span>Numerous studies have been done over the decades but there is no clear conclusion that organic foods are healthier, safer or tastier than conventionally grown ones. Organic or not, make fruit and vegetables a part of your daily diet.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1771729200,NULL,0,NULL,NULL,'push'),(68394,'Let\'s Recap.','<html><head></head><body><p style=\"margin-bottom:0;\">We learned how to get our money\'s worth of healthy groceries.</p><ul style=\"margin-top:0;\"><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p><span>Which would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1772334000,NULL,0,NULL,NULL,'push'),(68395,'Hey Tressa, did you manage to try out any of the dollar stretching ideas?','<html><head></head><body><ul><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1772766000,NULL,0,NULL,NULL,'push'),(68396,'Having a well-planned grocery list saves time and helps you stick to your healthy eating plan by making it easier for you to whip up healthier meals for yourself and your family.','<html><head></head><body><p><span>When shopping for healthy groceries, aim for balance, variety, and moderation.</span></p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">More tips:</span></p><ul style=\"padding-left:20px; margin-top:0;\"><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what you have first.</li><li>Then make a grocery list based on your meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to your list throughout the week, whenever you run out of something.</li><li>Buy only what you will use.</li><li>Stock up on pantry staples (e.g. rice, frozen meat/fish/vegetables, canned fish/beans, herbs).</li><li>Shop for perishables (e.g. fruit and vegetables) weekly.</li></ul><p><span>Is there another way to draw up a grocery list?</span></p><p><span>As a matter of fact, yes. But more of that next week.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1772938800,NULL,0,NULL,NULL,'push'),(68397,'Now let\'s get to your question on how to make an efficient grocery list in a few minutes.','<html><head></head><body><p>One way to do this is to organize your grocery list around the store layout. Base your list on how the same types of foods are grouped by aisle.</p><p><span> For Example,</span><br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Rice and Staples</span> aisle: <br>Healthier options include Brown rice, brown rice vermicelli, Whole wheat or whole-grain pasta.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cereals and Breakfast Foods</span> aisle: <br>Healthier options include Whole-grain or multigrain cereals, rolled oats or instant oatmeal, whole-grain cereal bars.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Bakery</span> aisle: <br>Healthier options include Whole wheat bread, pita pockets, Whole-grain flour tortillas.</p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span></p><ul style=\"margin-top:0; padding-left:20px;\"><li>Look for the words \"whole wheat\" or \"whole wheat flour\" as the first ingredient on the label.</li><li>Choose whole-grain breads that contain at least 3 to 4 grams of fiber and have fewer than 100 calories per slice.</li></ul><p>In the weeks to come, I can share more on how to use aisle layout to organise your grocery list.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1773543600,NULL,0,NULL,NULL,'push'),(68398,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Canned Goods</span> aisle:</span><br><span>Healthier options include Diced or whole peeled tomatoes, Beans/lentils/split peas, Tuna or salmon packed in spring water.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Limit consumption of canned foods as they tend to be higher in salt, sugar and fats.</li><li>Select products with the Healthier Choice Symbol.</li><li>When buying canned fruits, choose those that are packed in juice rather than syrup.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1774148400,NULL,0,NULL,NULL,'push'),(68399,'Organising grocery list by aisle','<html><head></head><body><p><em><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cooking Oils</span> aisle:</em><br><span>Healthier options include Canola oil, olive oil, peanut oil, rice bran oil, soybean oil, sesame oil.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Cooking oils have different smoke points.</li><li>For high-heat cooking (e.g. stir/deep frying), choose oils with higher smoke point such as peanut/rice bran/soybean oil.</li><li>Extra virgin olive oil has a relatively low smoke point of 199 °C and is not suitable for high-heat cooking.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1774753200,NULL,0,NULL,NULL,'push'),(68400,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Sauces and Condiments</span> aisle:</span><br><span>Many sauces, salad dressings and condiments are high in sodium, sugar and saturated fat.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>Opt for products that carry the \"Lower in Sodium\", \"Lower in Sugar\" or \"Lower in Saturated Fat\" Healthier Choice Symbol.</span><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Snacks and Crackers</span> aisle:</span><br><span>Healthier options include Whole-grain crackers, Dried fruit, nuts and seeds, peanut butter or almond butter, hummus, dark chocolates.</span></p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Drinks</span> aisle:</span><br><span>Healthier options include Unsweetened green and flavoured teas, Sparkling water.</span></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1775358000,NULL,0,NULL,NULL,'push'),(68401,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dairy and Eggs</span> aisle:<br>Healthier options include Skim or low-fat milk or soymilk, Fat-free or low-fat plain yogurt, Low-fat cheese, Eggs, Tofu, Butter or spread (a variety that doesn\'t contain hydrogenated oils).<br> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Meat and Seafood</span> aisle:<br>Healthier options include Skinless chicken breast, minced chicken, salmon, seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>If you buy red meat, choose the leanest cuts.</span><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Frozen Food</span> aisle:<br>Healthier options include Frozen fruit and vegetables, frozen meat/poultry/seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Use frozen vegetables to prepare soups, casseroles, and stews.</li><li>Low-fat frozen plain yogurt blended with frozen fruit makes a quick, healthy smoothie.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1775962800,NULL,0,NULL,NULL,'push'),(68402,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1776567600,NULL,0,NULL,NULL,'push'),(68403,'Let\'s Recap','<html><head></head><body><p><span>Having a well-planned grocery list saves time and helps you stick to your healthy eating plan.</span><br><br><span>Next time you go grocery shopping, which tips would you like to try out?</span></p><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1777172400,NULL,0,NULL,NULL,'push'),(68404,'Hey Tressa, did you manage to try out any of the grocery shopping tips?','<html><head></head><body><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul><p>If you have tried, how was your experience?<br>If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1777604400,NULL,0,NULL,NULL,'push'),(68405,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1777777200,NULL,0,NULL,NULL,'push'),(68406,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Tropical Fruits</span><br>Choose <strong>mangosteens</strong> that can be pressed in slightly.<br><strong>Mangoes</strong> should be slightly soft with an intense fragrance.<br><strong>Dragonfruits</strong> are evenly pink with fresh-looking petals and a soft stem.<br>Pick yellow <strong>papayas</strong> that are slightly soft when pressed and is heavy for its size.<br>Ripe <strong>pineapples</strong> are yellow with a pleasant aroma at the stem end.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1778382000,NULL,0,NULL,NULL,'push'),(68407,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Citrus Fruits</span><br>Choose <strong>citrus fruits</strong> that are firm, bright-looking with finely-textured peel and give off a strong fragrance.<br>Choose <strong>grapefruits</strong> that are redder and pomelos with a yellow tinge.<br>Choose navel <strong>oranges</strong> if you like them to be sweet and seedless.<br><strong>Kiwis</strong> are slightly soft when ripe and have taut skin.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1778986800,NULL,0,NULL,NULL,'push'),(68408,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Melons</span><br>Ripe <strong>watermelons</strong> look dull, not shiny and have dried stem ends. Look for the cream-coloured patch on the skin where they rested on the ground before harvest — the deeper the colour, the better it is.<br>Netted melons such as <strong>rockmelons and cantaloupes</strong> give off an intense fragrance when they are fully ripe. <br>Baby-skinned <strong>honeydew</strong> does not wear a scent when they are ripe. Instead, look for a yellow tinge in their waxy exterior. The stem end of <strong>all melons</strong> can be pressed in gently when they are ripe.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1779591600,NULL,0,NULL,NULL,'push'),(68409,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Berries</span><br>Choose <strong>blueberries</strong> that are plump, brightly-coloured with a whitish bloom. Shake the container of blueberries gently. If the berries don’t move freely, they may be soft or damaged.<br>Buy <strong>strawberries</strong> that give off a strong scent, an indication that they are sweet and ripe.<br>Look for shiny and firm <strong>blackberries</strong>.<br><strong>Raspberries</strong> should be firm, plump and deeply-coloured.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"  margin-top: 0;\"><li>Store blackberries and raspberries in a single layer as they bruise easily</li><li>Berries only stay fresh for a few days, so eat them fast! If not, freeze them for frozen sweet treats</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1780196400,NULL,0,NULL,NULL,'push'),(68410,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Stone fruits (e.g. plum, peach, nectarine, apricot)</span><br><span>Select <strong>stone fruits</strong> with firm skin that is not wrinkled. Softer fruits are sweeter and juicier. Leave them to ripen before storing them in the fridge. A deeper colour is a hint of ripeness, especially around the stem end.</span></p><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Other fruits</span></span><br><span><strong>Apples</strong> and <strong>pears</strong> should be firm and smooth-skinned.</span><br><span>A ripe <strong>passionfruit</strong> is plump, heavy for its size and wrinkled.</span><br><span>Look for plump <strong>grapes</strong> with a whitish bloom and healthier brown stems that still hold the fruit firmly.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1780801200,NULL,0,NULL,NULL,'push'),(68411,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dark green vegetables</span><br><strong>Leafy vegetables</strong> such as spinach should have bright green leaves and tender, crisp stems.<br>Fresh <strong>broccolis</strong> have compact, green florets and undamaged stems.<br><strong>Lettuce</strong> leaves should be crisp and bright.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1781406000,NULL,0,NULL,NULL,'push'),(68412,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Red and orange vegetables</span><br><span>Pick slim, medium-sized <strong>carrots</strong> which are well-formed and bright.</span><br><span><strong>Capsicums</strong> and <strong>chilli</strong> should be firm, deeply-coloured and glossy.</span><br><span>Avoid <strong>sweet potatoes</strong> with stringed “beards” as they are older and less tasty! Pick small to medium-sized ones with even tones.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1782010800,NULL,0,NULL,NULL,'push'),(68413,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Beans and peas</span><br>Edible bean pods such as <strong>French beans, green beans and snow peas</strong> taste better when they are tender and crisp with smaller beans within them<br><strong>Sweet peas</strong> are firm and crisp; they should not bend<br><strong>Dried beans</strong> should be free from mould, insects or discolouration</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1782615600,NULL,0,NULL,NULL,'push'),(68414,'How to choose fresh vegetables?','<html><head></head><body><p><strong><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Starchy vegetables</span></strong><br>Choose <strong>potatoes</strong> which are firm and have fewer “eyes”. They should not have any sprouts.<br>Look for bright and plump <strong>corn</strong> kernels when buying an ear of corn.<br>A lighter <strong>yam</strong> (or taro) is a better pick as it has less water and more likely to be “powdery”. When choosing yam that has been cut, look for the ones with more red veins inside.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1783220400,NULL,0,NULL,NULL,'push'),(68415,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Others</span><br><span>A good <strong>cabbage</strong> should be firm or even hard.</span><br><span>Tender <strong>asparagus</strong> are bright green with tightly closed spears that have darker green or purplish tips.</span><br><span><strong>Cauliflower</strong> heads should be firm and compact with no brown spots.</span><br><span>If you are buying the longer variety of <strong>eggplant</strong> (or brinjal), hold it up and test if it is springy (and young) by flicking it gently.</span><br><span>Smaller and shorter <strong>lady’s fingers</strong> are younger and crisper.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1783825200,NULL,0,NULL,NULL,'push'),(68416,'Let\'s Recap.','<html><head></head><body><p><span>Thinking of your favourite fruit and vegetables, which method/s would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1784430000,NULL,0,NULL,NULL,'push'),(68417,'Hey Tressa, did you manage to use any of the ideas to pick your favourite fruit and vegetables?','<html><head></head><body><p><span>If you have tried, how was your experience? <br>If not, you still have time to try at least one action. You can revisit the tips in the Notification Centre.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1784862000,NULL,0,NULL,NULL,'push'),(68418,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><span>Eating out is both fun and sociable. But it is easy to wind up overeating or indulging in a lot more fat, sugar, and salt than you normally would if you ate at home. In the weeks to come, I can share with you some clever tips to help you eat healthy at restaurants.</span></div><p style=\"margin-top:0px;margin-bottom:0px;\"><strong><em>Guide to healthy dining at restaurant</em></strong> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Plan ahead</span> <br><span>If you plan to eat out at your favourite restaurant, eat lighter meals through the rest of the day to allow for the additional calories you may indulge in.</span></p></body></html>','success','2025-08-25 07:54:39','2025-08-27 03:00:00',1,8965486,0,0,1756263600,NULL,0,NULL,NULL,'push'),(68419,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Be the first</em><br><span>Be the first to recommend a restaurant that serves healthier options or the first in your group to order a healthy dish. </span></div><div style=\"margin-bottom:20px;\"><span style=\" color: #FF98B7; font-style: italic; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\"><a href=\"https://www.healthhub.sg/live-healthy/5-healthier-cbd-lunchtime-dining-options\" style=\"color: #FF98B7; font-weight: 500; font-style: italic; text-decoration: underline; text-decoration-color: #FF98B7;\"> Which of your favourite restaurants offer healthier options? </a> </span></div><p style=\"margin-bottom:0px; margin-top:0px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Read the menu before you go</span><br><span>Choose your food before you get to the restaurant. It\'s easy to make unhealthy choices when hungry. The sight and smell of food and the food choices that others make can easily distract you from sticking to your health goals.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1756868400,NULL,0,NULL,NULL,'push'),(68420,'Guide to healthy dining at restaurant','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Choose dishes prepared using healthier methods </em><br><span>Avoid or limit items with names like crispy, deep-fried, in cream sauce, lemak, with coconut milk or in syrup as these tend to be higher in sugar and fat. </span></p><p><span>Ask the waiter or staff if you do not understand the fancy names of dishes. Dishes that are steamed, grilled, roasted or pan-fried are generally lower in calories. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1757473200,NULL,0,NULL,NULL,'push'),(68421,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order just enough</em><br><span>To control how much you eat, order just enough. You can always top up the food order later if needed. </span></div><div style=\"margin-bottom:20px;\"><span>Consider sharing food with someone else or ordering a half-portion if available. If you are going to a restaurant where you know the portions are huge, try ordering two appetizers instead of one main course. </span></div><p style=\"margin-top: 0px; margin-bottom:0px;\"><span>If there are extras, ask the waiter to bag it up if you do not like to see food wasted. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1758078000,NULL,0,NULL,NULL,'push'),(68422,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order a variety of dishes</span><br><span>Select a variety of items to make up a well-balanced meal. Include a staple, one or two vegetable side dishes, and one or two protein-rich items such as tofu, lentils, fish, chicken or lean meat. </span></div><div style=\"margin-bottom: 20px;\"><span>Consider starting with a salad, which not only adds greens to your meal but can also help to control your appetite. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Keep deep-fried or oily and fatty dishes to no more than one or two per meal. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1758682800,NULL,0,NULL,NULL,'push'),(68423,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Request for modifications </span><br><span>Don\'t be afraid to ask for modifications to your food.</span></div><div style=\"margin-bottom: 20px;\"><span>When placing your order, ask for your dishes to be prepared with less oil and sodium-containing seasonings. </span></div><p style=\"margin-bottom: 0px; margin-top:0px;\"><span>Considering swapping part of your meal, such as fries or potatoes, for extra vegetables or a salad. This can boost your fibre intake and reduce your calories consumed. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1759287600,NULL,0,NULL,NULL,'push'),(68424,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> Ask for sauces or dressings on the side </span><br> Sauces and dressings can be a hidden source of sugar, sodium and fat. Ask for sauces and dressings to be on the side so you can decide on the amount to add. </div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><a href=\"https://youtu.be/GXSO2-X4Cx4?si=w8JzuKUbLgvDTj0C\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Take less sauces and gravy - Watch Youtube Video</a></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1759892400,NULL,0,NULL,NULL,'push'),(68425,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span <span=\"\" style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Limit sugar-sweetened beverages and alcohol</span><br><span>For drinks, nothing beats water. Drinking water instead of sugar-sweetened drinks can help reduce your intake of calories and added sugar.</span></div><div style=\"margin-bottom: 20px;\"><span>If you would still like a beverage, opt for no-sugar or reduced-sugar drinks. For example, instead of a flavoured latte, go for a long black or a regular latte. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Alcoholic beverages are often high in calories with little nutritional value. If you must have a drink, limit yourself to 1 standard drink and opt for lower-calorie options like light beer and wine spritzers instead of sugary cocktails or mixed drinks. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1760497200,NULL,0,NULL,NULL,'push'),(68426,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">End the meal with fresh fruits instead of desserts</span><br><span>Craving a sweet treat at the end of your meal? Opt for a fresh fruit platter! It is a naturally sweet option that packs plenty of essential vitamins and minerals. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>If you still want to enjoy other desserts, select one with less sugar or syrup and cream. </span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1761102000,NULL,0,NULL,NULL,'push'),(68427,'Guide to healthy dining at restaurant','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Enjoy your favourite food in moderation</span><br><span>There will be times when you want to eat your favourite food and not worry about whether it is healthy or not. If you\'ve been eating healthily most of the time, go ahead and enjoy an occasional treat. Being flexible about your diet and food choices is linked with better overall health and weight management.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1761706800,NULL,0,NULL,NULL,'push'),(68428,'How do I avoid overeating when dining out?','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat mindfully</em><br><span>Slow down to give your body enough time to tell you that you are feeling full. Chew thoroughly and take the time to savour the aromas and flavours of your meal. Stop eating when you feel three-quarter full.</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1762311600,NULL,0,NULL,NULL,'push'),(68429,'What can I do to eat healthy at a fast-food restaurant?','<html><head></head><body><p><span>Fast food is convenient but tends to be high in calories, salt and fat. When consumed frequently and in excess, it may raise your risk of obesity, heart attack and other health issues.</span></p><div><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Resist upsizing the meal and drinks even though it may seem to make more monetary sense.</li><li>Select items that are grilled, not fried</li><li>Swap deep-fried sides (e.g. french fries or chips) for salad or steamed corn</li><li>If craving a sweet treat, opt for a cup of fresh fruits instead of ice-cream, sundae, or apple pie</li><li>Swap soft drinks for water</li><li>Ask for more vegetables in your burger</li></ul></div></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1762916400,NULL,0,NULL,NULL,'push'),(68430,'How do I control myself when dining at all-you-can-eat buffet?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat just enough </span><br><span>If you find yourself at all-you-can-eat buffet, select one favourite item from each section of the buffet line and eat no more than your regular portion. </span></p><p><span>Help yourself to small servings if you want to try the entire spread.</span></p><p><span>Eat slowly and take the time to savour your meal. Stop eating when you feel three-quarters full</span></p><p><span>If you are under pressure to keep eating to support your friends, eat slowly and steer the conversation away from your plate.</span></p><p><span>Spend more time socialising than eating</span></p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1763521200,NULL,0,NULL,NULL,'push'),(68431,'Choose one action to try out the next time you dine at a restaurant:','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1764126000,NULL,0,NULL,NULL,'push'),(68432,'Hey Tressa, did you manage to try out any of these healthy dining tips? ','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-25 07:54:39','2025-08-25 07:54:39',0,8965486,0,0,1764558000,NULL,0,NULL,NULL,'push'),(68433,'You may submit your Report Health Status from 25-Aug-2025. Complete it within 7 days from this date to refresh your Wellness Score.','','success','2025-08-25 09:45:00','2025-08-25 12:00:00',1,10935181,0,0,1756123200,NULL,0,NULL,NULL,'RHS_Notification'),(68434,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1756609200,NULL,0,NULL,NULL,'push'),(68435,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Products high in fibre are also high in wholegrains.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,1,1757214000,NULL,0,NULL,'\n         <p><strong >Answer: FALSE</strong> </br>Just because a product is high in fibre does not necessarily mean that it is wholegrain.\n      Food enriched or added with wheat or bran may be high in fibre but they are not wholegrain unless wholewheat or other wholegrains are used in the product.</p>\n    ','push'),(68436,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Brown bread has wholegrains.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,1,1757818800,NULL,0,NULL,'\n    <p><strong >Answer: FALSE</strong> <br/>\n      Don\'t judge a grain by its colour. Just because the bread is brown doesn\'t mean it is made of wholegrains.\n      Some bread or crackers may be brown because ​molasses or caramel colouring may have been added.\n      Don\'t forget that many wholegrain products such as cereals are light in colour.</p>\n\n      <p >Also, wholegrain food are not always dry and gritty.\n      You will be pleasantly surprised that some wholegrains are light and flaky like cereal grains while some may be dense with an enjoyable nutty flavour.</p>\n    ','push'),(68437,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span>Unfortunately, the ingredient list and the nutrition information panel (NIP) will not tell you the amount of wholegrains present in the food. So how?</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the word \"whole\"</span><br><span>The ingredient list will show the wholegrain as an ingredient e.g. wholewheat flour or whole oats. Look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on a product to ensure it is a wholegrain product. </span></p><p><span>The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>But there are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1758423600,NULL,0,NULL,NULL,'push'),(68438,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the Healthier Choice Symbol</span><br><span>Products carrying the \"Higher in Wholegrains\" symbol contain more wholegrains compared to similar products from the same food category.</span><br><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></p><span>When you see this symbol, it means that the:</span><ul style=\"margin-top:0\"><li>Bread and breakfast cereals contains at least 25% wholegrains.</li><li>Brown rice or oats contains 100% wholegrains.</li><li>Vermicelli (bee hoon) contains at least 80% wholegrains.</li><li>Biscuits contains at least 30% wholegrains.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1759028400,NULL,0,NULL,NULL,'push'),(68439,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1759633200,NULL,0,NULL,NULL,'push'),(68440,'How to limit sugar when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Both HCS and Nutri-Grade Mark are the same.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,1,1760238000,NULL,0,NULL,'\n  <p><strong >Answer: FALSE</strong> <br />\n      The Nutri-Grade mark is a labelling scheme for beverages based on their sugar and saturated fat content.</br>Beverages which are Nutri-Grade “C” or “D” will be labelled with a Nutri-Grade mark, while labelling of beverages graded “A” or “B” is optional.</br>When having beverages, choose HCS, Nutri-Grade “A”/”B” beverages or simply water to control your sugar and saturated fat intake.</p>\n\n      <span style=\"color: #FF98B7;\">Tip:<br />\n  </span>Explore the list of drink options that are lower in sugar and saturated fats at\n      <a  href=\"https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">\n       https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home \n      </a></p>\n    ','push'),(68441,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1760842800,NULL,0,NULL,NULL,'push'),(68442,'How to tell if a food is healthy by reading the label?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Why is it important to read and understand food labels?</span><br><span>Reading food labels is the first step to making sure your kitchen is stocked with healthier food products.</span></p><p><span>The front, back and sides of a packaged product are filled with clues that tell you what the food contains and how much you are eating. These information can guide you in making healthier purchases to cut back on sodium, choose wholegrain products, reduce unhealthy oil and fats, and limit sugar.</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">What happens if we do not read food labels?</span><br><span>Without reading food labels, we might eat more calories than necessary, misjudge portion sizes and unknowingly consume high amounts of sugar, salt and unhealthy fats. We might also accidentally consume allergens or ingredients we are sensitive to, triggering undesired reactions. </span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Not everything has a food label</span><br><span>Fresh produce like fruit and vegetables that have not been peeled, cut or processed, herbs and spices, tea, coffee, flours and alcoholic drinks may not have a food label. </span></p><p><span>Aim to eat at least 2 servings of fruit and 2 servings of vegetables a day. On the other hand, try to limit alcohol intake as excessive alcohol consumption can ruin your health. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1761447600,NULL,0,NULL,NULL,'push'),(68443,'Tips for understanding food labels','<html><head></head><body><p><span>1. Read the ingredients list</span><br><span>2. Check the nutrition information panel</span><br><span>3. Be aware of the calorie count</span><br><span>4. Find out the type of fat, and how much</span><br><span>6. Spot hidden sugar</span><br><span>7. Beware of salt</span><br><span>8. Know your portion size</span></p><p><span>In the coming weeks, I can share more with you how to read and understand food labels.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1762052400,NULL,0,NULL,NULL,'push'),(68444,'Read the ingredients list','<html><head></head><body><p><span>Most packaged foods have an ingredients list on the back or side of the packet. Everything that goes into your food will be listed in weight order from biggest to the smallest. </span></p><p><span>If the first few ingredients you see are cream, butter, fatty meat or cheese, then you know that saturated fat makes up the largest proportion of the product. </span></p><p><span>If you spot sugars (white or brown), syrups or concentrated fruit juice at the top of the ingredients list, then you know that the product you are eyeing is loaded with sugar.</span></p><p><span>Ingredients that appear further down the list are present in the product in small quantities but that does not mean their impact is small. For example, vitamins and minerals are often added to foods like breakfast cereals and dairy in small quantities but can make a positive impact on your diets. </span></p><p><span>Similarly, even small amounts of salt can add up to our maximum of one teaspoon of salt a day.</span></p><p><span style=\"color: #FF98B7; font-style: italic; font-weight: 500;\">Beware:</span><br><span>Manufacturers may use less common names for ingredients such as sodium chloride in place of salt or maltose and fructose for sugars so people may think a certain ingredient is not in the ingredient list.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1762657200,NULL,0,NULL,NULL,'push'),(68445,'Check the nutritional information panel','<html><head></head><body><p>Use the nutrition information panel to find out the amount of nutrients you are getting out of the product.</p><p><strong>Servings per package </strong><br>The number of servings in a single container or packet. There could be more than one serving per package. </p><p><strong>Serving size </strong><br>This measure of a single-serving is defined by the manufacturer and varies from product to product. Be aware that the single serving indicated may be less than what you would typically eat.</p><p>A packet of potato chips may contain 160 calories per 30g serving and contain ten servings. This means if you eat the whole packet, you would have had a whopping 1,600 calories. </p><p><strong>Comparing values</strong><br>The most important ones to look out for are the BIG FOUR: total fat, saturated fat, sugar and salt. These can affect your weight and blood pressure, contributing to your risk of heart disease and stroke. </p><p>But you can also compare other nutrients to make healthier choices, including unsaturated fats (the good kind of fats), wholegrains and fibre.</p><p>When choosing between items look at the ‘per 100g’ or ‘per 100ml’ column as it offers a fairer comparison rather than serving size, which varies between products. </p><p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><br>Focus on the key nutrients that are important to you.<br>If you are on a diet, look at the energy or calorie values. For people with high blood pressure, zoom in on the sodium value or check the saturated fat and cholesterol amounts if you have high cholesterol.</p><p><a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Find out more at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1763262000,NULL,0,NULL,NULL,'push'),(68446,'Be aware of the calorie count ','<html><head></head><body><p><span>Calories (kcal) are a measure of how much energy is in a product. </span></p><p><span>Generally, women need around 1800 calories a day and men need around 2200 calories. But, the exact amounts needed by different persons will vary depending on their age, gender, height, weight and activity level.</span></p><p><span>Constant calorie counting isn\'t necessary but it\'s good to be aware of your calorie intake, especially if you want to maintain a healthy weight or lose a few extra pounds if necessary.</span></p><p><span>One way is to check the caloric content of the products you eat using \"per portion\" information, but do check how the manufacturer\'s portion compares with the portion you actually eat. For example, the manufacturer\'s portion might be two squares of chocolates but the actual amount of chocolates you eat might be much more.</span></p><p><span>Another way is to look for products carrying the Healthier Choice Symbol (HCS) with this tagline, such as crisps/chips where each individually packaged portion is less than or equal to 100 calories. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_100_calories.jpg\" alt=\"Less Than 100\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Products carrying HCS with this tagline are ice cream products that are both lower in sugar compared to similar products in the same food category and less than or equal to 200 calories per portion. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_200_Calories.jpg\" alt=\"Less Than 200\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Choosing your snacks wisely can keep your energy levels up without piling on added calories. </span><br><span>Do you recall seeing this HCS label on the last snack you ate? </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1763866800,NULL,0,NULL,NULL,'push'),(68447,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1764471600,NULL,0,NULL,NULL,'push'),(68448,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1765076400,NULL,0,NULL,NULL,'push'),(68449,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1765681200,NULL,0,NULL,NULL,'push'),(68450,'Look out for \'whole\' in the ingredient list  ','<html><head></head><body><p><span>To identify wholegrain products, look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on the ingredient list. The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>There are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p><p><span>Another way is to look for products carrying the \"Higher in Wholegrains\" Healthier Choice Symbol, which contain more wholegrains compared to similar products from the same food category. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p> <a href=\"https://youtu.be/XmbV3VeDjM4?si=0Z4aQd2Wc-QqhPgp\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Go Wholegrain - Watch Youtube Video</a></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1766286000,NULL,0,NULL,NULL,'push'),(68451,'Know your portion size ','<html><head></head><body><p><span>You can find the amount of nutrition per portion on the nutrition information panel. The portion size is recommended by the manufacturer, and can vary between brands.</span></p><p><span>Be aware that the manufacturer\'s portion size might be smaller than yours, which means that even if a product looks healthy, if you have more than this amount, you may still end up consuming more calories, saturated fat, sugar or salt than you realize.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1766890800,NULL,0,NULL,NULL,'push'),(68452,'Let\'s Recap. ','<html><head></head><body><p>Shopping for healthy groceries allows you to cut back on sodium, find wholegrain products, reduce unhealthy oil and fats and limit sugar. One way is to understand food labels.<br><br>In the coming week, which method would you like to try out?</p><ul style=\"margin-top: 0;\"><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1767495600,NULL,0,NULL,NULL,'push'),(68453,'Hey Llewellyn, did you manage to try out any of these grocery shopping methods?','<html><head></head><body><ul><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one method.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1767927600,NULL,0,NULL,NULL,'push'),(68454,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #1 Don\'t shop on an empty stomach</span><br><span>It\'s harder to resist buying higher-fat, higher-calorie snack items when you\'re hungry. Shop after you\'ve eaten a good meal. Drink some water or munch on a fruit before you shop.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1768100400,NULL,0,NULL,NULL,'push'),(68455,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Make a shopping list</span><br><span>Make a shopping list to reduce the urge to buy on impulse. Having a well-planned grocery list also saves time and helps you stick to your healthy eating plan.</span></p><span style=\"color: #FF98B7; font-weight: 500; \">Tips:</span><ul style=\" margin-top: 0;\"><li>Buy only what you will use, not because it is on promotion.</li><li>Resist \"buy one get one\" unless it is a staple.</li><li>Use store apps to compare prices.</li><li>Choose house-brands.</li><li>Select items with longer use-by date.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1768705200,NULL,0,NULL,NULL,'push'),(68456,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Go fresh </span><br>Choose fresh or frozen produce and less processed, wholesome foods (e.g. grains, nuts, eggs, herbs and spices) wherever possible.<br><br>Fresh produce are generally better than processed and ready-to-eat foods so that you know exactly what goes into your meal when you cook at home. They are also lower in fat, sugars and additives.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top:0;\"><li>Spend more time in the fresh produce section.</li><li>Limit your time in the aisles that stock snack food/candy and canned/processed foods.</li><li>Stick reminders on your fridge so that perishable fruit and vegetables are not forgotten in your fridge.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1769310000,NULL,0,NULL,NULL,'push'),(68457,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#4 Frozen or fresh </span><br>Frozen fruits and vegetables are flash-frozen to lock in their nutrients immediately after harvest. Fresh or frozen, fruit and vegetables are nutritious and healthier food choices. <br><br>Frozen produce is easy to keep in the freezer for when needed and will keep for far longer than fresh produce, helping to reduce food waste and save money. For out-of-season items, they can be cheaper than fresh produce.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\"margin-top:0\"><li>Buy enough to ensure everyone in your family have sufficient servings.</li><li>Eat a rainbow. Choose fruit and vegetables of different colours to get the maximum nutrients you need.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1769914800,NULL,0,NULL,NULL,'push'),(68458,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#5 Shop in season. Shop local.</span><br><span>Buy fruits and vegetables in season as they peak in flavour and nutrients, and are cheaper.</span></p><p><span>Most of our fruits and vegetables come from Malaysia, China, USA and Australia while local farms produce 12 percent of our leafy vegetables. Shorter time from source to market means fewer nutrients and flavour are lost in transit.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1770519600,NULL,0,NULL,NULL,'push'),(68459,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #6 Check food labels </span><br>If you have to buy processed or packaged foods, look out for the Healthier Choice Symbol (HCS). </p><p>The HCS can be found on the packaging of products such as convenience meals, sauces, drinks, snacks and breakfast cereals. Do you recall seeing the HCS on the items you bought recently? </p><p>Use the HCS to compare similar products so that you can choose the healthiest option. </p><p>You can also use the Nutrition Information Panel (NIP) to find out the amount of calories and nutrients you are getting out of each serving of food. <a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" target=\"_blank\" rel=\"noopener noreferrer\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Learn how to read the NIP at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1771124400,NULL,0,NULL,NULL,'push'),(68460,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#7 To buy organic produce or not</span><br><span>Numerous studies have been done over the decades but there is no clear conclusion that organic foods are healthier, safer or tastier than conventionally grown ones. Organic or not, make fruit and vegetables a part of your daily diet.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1771729200,NULL,0,NULL,NULL,'push'),(68461,'Let\'s Recap.','<html><head></head><body><p style=\"margin-bottom:0;\">We learned how to get our money\'s worth of healthy groceries.</p><ul style=\"margin-top:0;\"><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p><span>Which would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1772334000,NULL,0,NULL,NULL,'push'),(68462,'Hey Llewellyn, did you manage to try out any of the dollar stretching ideas?','<html><head></head><body><ul><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1772766000,NULL,0,NULL,NULL,'push'),(68463,'Having a well-planned grocery list saves time and helps you stick to your healthy eating plan by making it easier for you to whip up healthier meals for yourself and your family.','<html><head></head><body><p><span>When shopping for healthy groceries, aim for balance, variety, and moderation.</span></p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">More tips:</span></p><ul style=\"padding-left:20px; margin-top:0;\"><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what you have first.</li><li>Then make a grocery list based on your meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to your list throughout the week, whenever you run out of something.</li><li>Buy only what you will use.</li><li>Stock up on pantry staples (e.g. rice, frozen meat/fish/vegetables, canned fish/beans, herbs).</li><li>Shop for perishables (e.g. fruit and vegetables) weekly.</li></ul><p><span>Is there another way to draw up a grocery list?</span></p><p><span>As a matter of fact, yes. But more of that next week.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1772938800,NULL,0,NULL,NULL,'push'),(68464,'Now let\'s get to your question on how to make an efficient grocery list in a few minutes.','<html><head></head><body><p>One way to do this is to organize your grocery list around the store layout. Base your list on how the same types of foods are grouped by aisle.</p><p><span> For Example,</span><br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Rice and Staples</span> aisle: <br>Healthier options include Brown rice, brown rice vermicelli, Whole wheat or whole-grain pasta.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cereals and Breakfast Foods</span> aisle: <br>Healthier options include Whole-grain or multigrain cereals, rolled oats or instant oatmeal, whole-grain cereal bars.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Bakery</span> aisle: <br>Healthier options include Whole wheat bread, pita pockets, Whole-grain flour tortillas.</p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span></p><ul style=\"margin-top:0; padding-left:20px;\"><li>Look for the words \"whole wheat\" or \"whole wheat flour\" as the first ingredient on the label.</li><li>Choose whole-grain breads that contain at least 3 to 4 grams of fiber and have fewer than 100 calories per slice.</li></ul><p>In the weeks to come, I can share more on how to use aisle layout to organise your grocery list.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1773543600,NULL,0,NULL,NULL,'push'),(68465,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Canned Goods</span> aisle:</span><br><span>Healthier options include Diced or whole peeled tomatoes, Beans/lentils/split peas, Tuna or salmon packed in spring water.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Limit consumption of canned foods as they tend to be higher in salt, sugar and fats.</li><li>Select products with the Healthier Choice Symbol.</li><li>When buying canned fruits, choose those that are packed in juice rather than syrup.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1774148400,NULL,0,NULL,NULL,'push'),(68466,'Organising grocery list by aisle','<html><head></head><body><p><em><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cooking Oils</span> aisle:</em><br><span>Healthier options include Canola oil, olive oil, peanut oil, rice bran oil, soybean oil, sesame oil.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Cooking oils have different smoke points.</li><li>For high-heat cooking (e.g. stir/deep frying), choose oils with higher smoke point such as peanut/rice bran/soybean oil.</li><li>Extra virgin olive oil has a relatively low smoke point of 199 °C and is not suitable for high-heat cooking.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1774753200,NULL,0,NULL,NULL,'push'),(68467,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Sauces and Condiments</span> aisle:</span><br><span>Many sauces, salad dressings and condiments are high in sodium, sugar and saturated fat.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>Opt for products that carry the \"Lower in Sodium\", \"Lower in Sugar\" or \"Lower in Saturated Fat\" Healthier Choice Symbol.</span><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Snacks and Crackers</span> aisle:</span><br><span>Healthier options include Whole-grain crackers, Dried fruit, nuts and seeds, peanut butter or almond butter, hummus, dark chocolates.</span></p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Drinks</span> aisle:</span><br><span>Healthier options include Unsweetened green and flavoured teas, Sparkling water.</span></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1775358000,NULL,0,NULL,NULL,'push'),(68468,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dairy and Eggs</span> aisle:<br>Healthier options include Skim or low-fat milk or soymilk, Fat-free or low-fat plain yogurt, Low-fat cheese, Eggs, Tofu, Butter or spread (a variety that doesn\'t contain hydrogenated oils).<br> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Meat and Seafood</span> aisle:<br>Healthier options include Skinless chicken breast, minced chicken, salmon, seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>If you buy red meat, choose the leanest cuts.</span><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Frozen Food</span> aisle:<br>Healthier options include Frozen fruit and vegetables, frozen meat/poultry/seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Use frozen vegetables to prepare soups, casseroles, and stews.</li><li>Low-fat frozen plain yogurt blended with frozen fruit makes a quick, healthy smoothie.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1775962800,NULL,0,NULL,NULL,'push'),(68469,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1776567600,NULL,0,NULL,NULL,'push'),(68470,'Let\'s Recap','<html><head></head><body><p><span>Having a well-planned grocery list saves time and helps you stick to your healthy eating plan.</span><br><br><span>Next time you go grocery shopping, which tips would you like to try out?</span></p><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1777172400,NULL,0,NULL,NULL,'push'),(68471,'Hey Llewellyn, did you manage to try out any of the grocery shopping tips?','<html><head></head><body><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul><p>If you have tried, how was your experience?<br>If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1777604400,NULL,0,NULL,NULL,'push'),(68472,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1777777200,NULL,0,NULL,NULL,'push'),(68473,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Tropical Fruits</span><br>Choose <strong>mangosteens</strong> that can be pressed in slightly.<br><strong>Mangoes</strong> should be slightly soft with an intense fragrance.<br><strong>Dragonfruits</strong> are evenly pink with fresh-looking petals and a soft stem.<br>Pick yellow <strong>papayas</strong> that are slightly soft when pressed and is heavy for its size.<br>Ripe <strong>pineapples</strong> are yellow with a pleasant aroma at the stem end.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1778382000,NULL,0,NULL,NULL,'push'),(68474,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Citrus Fruits</span><br>Choose <strong>citrus fruits</strong> that are firm, bright-looking with finely-textured peel and give off a strong fragrance.<br>Choose <strong>grapefruits</strong> that are redder and pomelos with a yellow tinge.<br>Choose navel <strong>oranges</strong> if you like them to be sweet and seedless.<br><strong>Kiwis</strong> are slightly soft when ripe and have taut skin.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1778986800,NULL,0,NULL,NULL,'push'),(68475,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Melons</span><br>Ripe <strong>watermelons</strong> look dull, not shiny and have dried stem ends. Look for the cream-coloured patch on the skin where they rested on the ground before harvest — the deeper the colour, the better it is.<br>Netted melons such as <strong>rockmelons and cantaloupes</strong> give off an intense fragrance when they are fully ripe. <br>Baby-skinned <strong>honeydew</strong> does not wear a scent when they are ripe. Instead, look for a yellow tinge in their waxy exterior. The stem end of <strong>all melons</strong> can be pressed in gently when they are ripe.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1779591600,NULL,0,NULL,NULL,'push'),(68476,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Berries</span><br>Choose <strong>blueberries</strong> that are plump, brightly-coloured with a whitish bloom. Shake the container of blueberries gently. If the berries don’t move freely, they may be soft or damaged.<br>Buy <strong>strawberries</strong> that give off a strong scent, an indication that they are sweet and ripe.<br>Look for shiny and firm <strong>blackberries</strong>.<br><strong>Raspberries</strong> should be firm, plump and deeply-coloured.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"  margin-top: 0;\"><li>Store blackberries and raspberries in a single layer as they bruise easily</li><li>Berries only stay fresh for a few days, so eat them fast! If not, freeze them for frozen sweet treats</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1780196400,NULL,0,NULL,NULL,'push'),(68477,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Stone fruits (e.g. plum, peach, nectarine, apricot)</span><br><span>Select <strong>stone fruits</strong> with firm skin that is not wrinkled. Softer fruits are sweeter and juicier. Leave them to ripen before storing them in the fridge. A deeper colour is a hint of ripeness, especially around the stem end.</span></p><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Other fruits</span></span><br><span><strong>Apples</strong> and <strong>pears</strong> should be firm and smooth-skinned.</span><br><span>A ripe <strong>passionfruit</strong> is plump, heavy for its size and wrinkled.</span><br><span>Look for plump <strong>grapes</strong> with a whitish bloom and healthier brown stems that still hold the fruit firmly.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1780801200,NULL,0,NULL,NULL,'push'),(68478,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dark green vegetables</span><br><strong>Leafy vegetables</strong> such as spinach should have bright green leaves and tender, crisp stems.<br>Fresh <strong>broccolis</strong> have compact, green florets and undamaged stems.<br><strong>Lettuce</strong> leaves should be crisp and bright.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1781406000,NULL,0,NULL,NULL,'push'),(68479,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Red and orange vegetables</span><br><span>Pick slim, medium-sized <strong>carrots</strong> which are well-formed and bright.</span><br><span><strong>Capsicums</strong> and <strong>chilli</strong> should be firm, deeply-coloured and glossy.</span><br><span>Avoid <strong>sweet potatoes</strong> with stringed “beards” as they are older and less tasty! Pick small to medium-sized ones with even tones.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1782010800,NULL,0,NULL,NULL,'push'),(68480,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Beans and peas</span><br>Edible bean pods such as <strong>French beans, green beans and snow peas</strong> taste better when they are tender and crisp with smaller beans within them<br><strong>Sweet peas</strong> are firm and crisp; they should not bend<br><strong>Dried beans</strong> should be free from mould, insects or discolouration</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1782615600,NULL,0,NULL,NULL,'push'),(68481,'How to choose fresh vegetables?','<html><head></head><body><p><strong><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Starchy vegetables</span></strong><br>Choose <strong>potatoes</strong> which are firm and have fewer “eyes”. They should not have any sprouts.<br>Look for bright and plump <strong>corn</strong> kernels when buying an ear of corn.<br>A lighter <strong>yam</strong> (or taro) is a better pick as it has less water and more likely to be “powdery”. When choosing yam that has been cut, look for the ones with more red veins inside.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1783220400,NULL,0,NULL,NULL,'push'),(68482,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Others</span><br><span>A good <strong>cabbage</strong> should be firm or even hard.</span><br><span>Tender <strong>asparagus</strong> are bright green with tightly closed spears that have darker green or purplish tips.</span><br><span><strong>Cauliflower</strong> heads should be firm and compact with no brown spots.</span><br><span>If you are buying the longer variety of <strong>eggplant</strong> (or brinjal), hold it up and test if it is springy (and young) by flicking it gently.</span><br><span>Smaller and shorter <strong>lady’s fingers</strong> are younger and crisper.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1783825200,NULL,0,NULL,NULL,'push'),(68483,'Let\'s Recap.','<html><head></head><body><p><span>Thinking of your favourite fruit and vegetables, which method/s would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1784430000,NULL,0,NULL,NULL,'push'),(68484,'Hey Llewellyn, did you manage to use any of the ideas to pick your favourite fruit and vegetables?','<html><head></head><body><p><span>If you have tried, how was your experience? <br>If not, you still have time to try at least one action. You can revisit the tips in the Notification Centre.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1784862000,NULL,0,NULL,NULL,'push'),(68485,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><span>Eating out is both fun and sociable. But it is easy to wind up overeating or indulging in a lot more fat, sugar, and salt than you normally would if you ate at home. In the weeks to come, I can share with you some clever tips to help you eat healthy at restaurants.</span></div><p style=\"margin-top:0px;margin-bottom:0px;\"><strong><em>Guide to healthy dining at restaurant</em></strong> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Plan ahead</span> <br><span>If you plan to eat out at your favourite restaurant, eat lighter meals through the rest of the day to allow for the additional calories you may indulge in.</span></p></body></html>','success','2025-08-25 12:04:46','2025-08-27 03:00:00',1,7239142,0,0,1756263600,NULL,0,NULL,NULL,'push'),(68486,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Be the first</em><br><span>Be the first to recommend a restaurant that serves healthier options or the first in your group to order a healthy dish. </span></div><div style=\"margin-bottom:20px;\"><span style=\" color: #FF98B7; font-style: italic; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\"><a href=\"https://www.healthhub.sg/live-healthy/5-healthier-cbd-lunchtime-dining-options\" style=\"color: #FF98B7; font-weight: 500; font-style: italic; text-decoration: underline; text-decoration-color: #FF98B7;\"> Which of your favourite restaurants offer healthier options? </a> </span></div><p style=\"margin-bottom:0px; margin-top:0px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Read the menu before you go</span><br><span>Choose your food before you get to the restaurant. It\'s easy to make unhealthy choices when hungry. The sight and smell of food and the food choices that others make can easily distract you from sticking to your health goals.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1756868400,NULL,0,NULL,NULL,'push'),(68487,'Guide to healthy dining at restaurant','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Choose dishes prepared using healthier methods </em><br><span>Avoid or limit items with names like crispy, deep-fried, in cream sauce, lemak, with coconut milk or in syrup as these tend to be higher in sugar and fat. </span></p><p><span>Ask the waiter or staff if you do not understand the fancy names of dishes. Dishes that are steamed, grilled, roasted or pan-fried are generally lower in calories. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1757473200,NULL,0,NULL,NULL,'push'),(68488,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order just enough</em><br><span>To control how much you eat, order just enough. You can always top up the food order later if needed. </span></div><div style=\"margin-bottom:20px;\"><span>Consider sharing food with someone else or ordering a half-portion if available. If you are going to a restaurant where you know the portions are huge, try ordering two appetizers instead of one main course. </span></div><p style=\"margin-top: 0px; margin-bottom:0px;\"><span>If there are extras, ask the waiter to bag it up if you do not like to see food wasted. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1758078000,NULL,0,NULL,NULL,'push'),(68489,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order a variety of dishes</span><br><span>Select a variety of items to make up a well-balanced meal. Include a staple, one or two vegetable side dishes, and one or two protein-rich items such as tofu, lentils, fish, chicken or lean meat. </span></div><div style=\"margin-bottom: 20px;\"><span>Consider starting with a salad, which not only adds greens to your meal but can also help to control your appetite. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Keep deep-fried or oily and fatty dishes to no more than one or two per meal. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1758682800,NULL,0,NULL,NULL,'push'),(68490,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Request for modifications </span><br><span>Don\'t be afraid to ask for modifications to your food.</span></div><div style=\"margin-bottom: 20px;\"><span>When placing your order, ask for your dishes to be prepared with less oil and sodium-containing seasonings. </span></div><p style=\"margin-bottom: 0px; margin-top:0px;\"><span>Considering swapping part of your meal, such as fries or potatoes, for extra vegetables or a salad. This can boost your fibre intake and reduce your calories consumed. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1759287600,NULL,0,NULL,NULL,'push'),(68491,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> Ask for sauces or dressings on the side </span><br> Sauces and dressings can be a hidden source of sugar, sodium and fat. Ask for sauces and dressings to be on the side so you can decide on the amount to add. </div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><a href=\"https://youtu.be/GXSO2-X4Cx4?si=w8JzuKUbLgvDTj0C\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Take less sauces and gravy - Watch Youtube Video</a></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1759892400,NULL,0,NULL,NULL,'push'),(68492,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span <span=\"\" style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Limit sugar-sweetened beverages and alcohol</span><br><span>For drinks, nothing beats water. Drinking water instead of sugar-sweetened drinks can help reduce your intake of calories and added sugar.</span></div><div style=\"margin-bottom: 20px;\"><span>If you would still like a beverage, opt for no-sugar or reduced-sugar drinks. For example, instead of a flavoured latte, go for a long black or a regular latte. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Alcoholic beverages are often high in calories with little nutritional value. If you must have a drink, limit yourself to 1 standard drink and opt for lower-calorie options like light beer and wine spritzers instead of sugary cocktails or mixed drinks. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1760497200,NULL,0,NULL,NULL,'push'),(68493,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">End the meal with fresh fruits instead of desserts</span><br><span>Craving a sweet treat at the end of your meal? Opt for a fresh fruit platter! It is a naturally sweet option that packs plenty of essential vitamins and minerals. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>If you still want to enjoy other desserts, select one with less sugar or syrup and cream. </span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1761102000,NULL,0,NULL,NULL,'push'),(68494,'Guide to healthy dining at restaurant','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Enjoy your favourite food in moderation</span><br><span>There will be times when you want to eat your favourite food and not worry about whether it is healthy or not. If you\'ve been eating healthily most of the time, go ahead and enjoy an occasional treat. Being flexible about your diet and food choices is linked with better overall health and weight management.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1761706800,NULL,0,NULL,NULL,'push'),(68495,'How do I avoid overeating when dining out?','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat mindfully</em><br><span>Slow down to give your body enough time to tell you that you are feeling full. Chew thoroughly and take the time to savour the aromas and flavours of your meal. Stop eating when you feel three-quarter full.</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1762311600,NULL,0,NULL,NULL,'push'),(68496,'What can I do to eat healthy at a fast-food restaurant?','<html><head></head><body><p><span>Fast food is convenient but tends to be high in calories, salt and fat. When consumed frequently and in excess, it may raise your risk of obesity, heart attack and other health issues.</span></p><div><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Resist upsizing the meal and drinks even though it may seem to make more monetary sense.</li><li>Select items that are grilled, not fried</li><li>Swap deep-fried sides (e.g. french fries or chips) for salad or steamed corn</li><li>If craving a sweet treat, opt for a cup of fresh fruits instead of ice-cream, sundae, or apple pie</li><li>Swap soft drinks for water</li><li>Ask for more vegetables in your burger</li></ul></div></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1762916400,NULL,0,NULL,NULL,'push'),(68497,'How do I control myself when dining at all-you-can-eat buffet?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat just enough </span><br><span>If you find yourself at all-you-can-eat buffet, select one favourite item from each section of the buffet line and eat no more than your regular portion. </span></p><p><span>Help yourself to small servings if you want to try the entire spread.</span></p><p><span>Eat slowly and take the time to savour your meal. Stop eating when you feel three-quarters full</span></p><p><span>If you are under pressure to keep eating to support your friends, eat slowly and steer the conversation away from your plate.</span></p><p><span>Spend more time socialising than eating</span></p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1763521200,NULL,0,NULL,NULL,'push'),(68498,'Choose one action to try out the next time you dine at a restaurant:','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1764126000,NULL,0,NULL,NULL,'push'),(68499,'Hey Llewellyn, did you manage to try out any of these healthy dining tips? ','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-25 12:04:46','2025-08-25 12:04:46',0,7239142,0,0,1764558000,NULL,0,NULL,NULL,'push'),(68500,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1756609200,NULL,0,NULL,NULL,'push'),(68501,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Products high in fibre are also high in wholegrains.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,1,1757214000,NULL,0,NULL,'\n         <p><strong >Answer: FALSE</strong> </br>Just because a product is high in fibre does not necessarily mean that it is wholegrain.\n      Food enriched or added with wheat or bran may be high in fibre but they are not wholegrain unless wholewheat or other wholegrains are used in the product.</p>\n    ','push'),(68502,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Brown bread has wholegrains.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,1,1757818800,NULL,0,NULL,'\n    <p><strong >Answer: FALSE</strong> <br/>\n      Don\'t judge a grain by its colour. Just because the bread is brown doesn\'t mean it is made of wholegrains.\n      Some bread or crackers may be brown because ​molasses or caramel colouring may have been added.\n      Don\'t forget that many wholegrain products such as cereals are light in colour.</p>\n\n      <p >Also, wholegrain food are not always dry and gritty.\n      You will be pleasantly surprised that some wholegrains are light and flaky like cereal grains while some may be dense with an enjoyable nutty flavour.</p>\n    ','push'),(68503,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span>Unfortunately, the ingredient list and the nutrition information panel (NIP) will not tell you the amount of wholegrains present in the food. So how?</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the word \"whole\"</span><br><span>The ingredient list will show the wholegrain as an ingredient e.g. wholewheat flour or whole oats. Look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on a product to ensure it is a wholegrain product. </span></p><p><span>The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>But there are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1758423600,NULL,0,NULL,NULL,'push'),(68504,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the Healthier Choice Symbol</span><br><span>Products carrying the \"Higher in Wholegrains\" symbol contain more wholegrains compared to similar products from the same food category.</span><br><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></p><span>When you see this symbol, it means that the:</span><ul style=\"margin-top:0\"><li>Bread and breakfast cereals contains at least 25% wholegrains.</li><li>Brown rice or oats contains 100% wholegrains.</li><li>Vermicelli (bee hoon) contains at least 80% wholegrains.</li><li>Biscuits contains at least 30% wholegrains.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1759028400,NULL,0,NULL,NULL,'push'),(68505,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1759633200,NULL,0,NULL,NULL,'push'),(68506,'How to limit sugar when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Both HCS and Nutri-Grade Mark are the same.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,1,1760238000,NULL,0,NULL,'\n  <p><strong >Answer: FALSE</strong> <br />\n      The Nutri-Grade mark is a labelling scheme for beverages based on their sugar and saturated fat content.</br>Beverages which are Nutri-Grade “C” or “D” will be labelled with a Nutri-Grade mark, while labelling of beverages graded “A” or “B” is optional.</br>When having beverages, choose HCS, Nutri-Grade “A”/”B” beverages or simply water to control your sugar and saturated fat intake.</p>\n\n      <span style=\"color: #FF98B7;\">Tip:<br />\n  </span>Explore the list of drink options that are lower in sugar and saturated fats at\n      <a  href=\"https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">\n       https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home \n      </a></p>\n    ','push'),(68507,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1760842800,NULL,0,NULL,NULL,'push'),(68508,'How to tell if a food is healthy by reading the label?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Why is it important to read and understand food labels?</span><br><span>Reading food labels is the first step to making sure your kitchen is stocked with healthier food products.</span></p><p><span>The front, back and sides of a packaged product are filled with clues that tell you what the food contains and how much you are eating. These information can guide you in making healthier purchases to cut back on sodium, choose wholegrain products, reduce unhealthy oil and fats, and limit sugar.</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">What happens if we do not read food labels?</span><br><span>Without reading food labels, we might eat more calories than necessary, misjudge portion sizes and unknowingly consume high amounts of sugar, salt and unhealthy fats. We might also accidentally consume allergens or ingredients we are sensitive to, triggering undesired reactions. </span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Not everything has a food label</span><br><span>Fresh produce like fruit and vegetables that have not been peeled, cut or processed, herbs and spices, tea, coffee, flours and alcoholic drinks may not have a food label. </span></p><p><span>Aim to eat at least 2 servings of fruit and 2 servings of vegetables a day. On the other hand, try to limit alcohol intake as excessive alcohol consumption can ruin your health. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1761447600,NULL,0,NULL,NULL,'push'),(68509,'Tips for understanding food labels','<html><head></head><body><p><span>1. Read the ingredients list</span><br><span>2. Check the nutrition information panel</span><br><span>3. Be aware of the calorie count</span><br><span>4. Find out the type of fat, and how much</span><br><span>6. Spot hidden sugar</span><br><span>7. Beware of salt</span><br><span>8. Know your portion size</span></p><p><span>In the coming weeks, I can share more with you how to read and understand food labels.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1762052400,NULL,0,NULL,NULL,'push'),(68510,'Read the ingredients list','<html><head></head><body><p><span>Most packaged foods have an ingredients list on the back or side of the packet. Everything that goes into your food will be listed in weight order from biggest to the smallest. </span></p><p><span>If the first few ingredients you see are cream, butter, fatty meat or cheese, then you know that saturated fat makes up the largest proportion of the product. </span></p><p><span>If you spot sugars (white or brown), syrups or concentrated fruit juice at the top of the ingredients list, then you know that the product you are eyeing is loaded with sugar.</span></p><p><span>Ingredients that appear further down the list are present in the product in small quantities but that does not mean their impact is small. For example, vitamins and minerals are often added to foods like breakfast cereals and dairy in small quantities but can make a positive impact on your diets. </span></p><p><span>Similarly, even small amounts of salt can add up to our maximum of one teaspoon of salt a day.</span></p><p><span style=\"color: #FF98B7; font-style: italic; font-weight: 500;\">Beware:</span><br><span>Manufacturers may use less common names for ingredients such as sodium chloride in place of salt or maltose and fructose for sugars so people may think a certain ingredient is not in the ingredient list.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1762657200,NULL,0,NULL,NULL,'push'),(68511,'Check the nutritional information panel','<html><head></head><body><p>Use the nutrition information panel to find out the amount of nutrients you are getting out of the product.</p><p><strong>Servings per package </strong><br>The number of servings in a single container or packet. There could be more than one serving per package. </p><p><strong>Serving size </strong><br>This measure of a single-serving is defined by the manufacturer and varies from product to product. Be aware that the single serving indicated may be less than what you would typically eat.</p><p>A packet of potato chips may contain 160 calories per 30g serving and contain ten servings. This means if you eat the whole packet, you would have had a whopping 1,600 calories. </p><p><strong>Comparing values</strong><br>The most important ones to look out for are the BIG FOUR: total fat, saturated fat, sugar and salt. These can affect your weight and blood pressure, contributing to your risk of heart disease and stroke. </p><p>But you can also compare other nutrients to make healthier choices, including unsaturated fats (the good kind of fats), wholegrains and fibre.</p><p>When choosing between items look at the ‘per 100g’ or ‘per 100ml’ column as it offers a fairer comparison rather than serving size, which varies between products. </p><p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><br>Focus on the key nutrients that are important to you.<br>If you are on a diet, look at the energy or calorie values. For people with high blood pressure, zoom in on the sodium value or check the saturated fat and cholesterol amounts if you have high cholesterol.</p><p><a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Find out more at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1763262000,NULL,0,NULL,NULL,'push'),(68512,'Be aware of the calorie count ','<html><head></head><body><p><span>Calories (kcal) are a measure of how much energy is in a product. </span></p><p><span>Generally, women need around 1800 calories a day and men need around 2200 calories. But, the exact amounts needed by different persons will vary depending on their age, gender, height, weight and activity level.</span></p><p><span>Constant calorie counting isn\'t necessary but it\'s good to be aware of your calorie intake, especially if you want to maintain a healthy weight or lose a few extra pounds if necessary.</span></p><p><span>One way is to check the caloric content of the products you eat using \"per portion\" information, but do check how the manufacturer\'s portion compares with the portion you actually eat. For example, the manufacturer\'s portion might be two squares of chocolates but the actual amount of chocolates you eat might be much more.</span></p><p><span>Another way is to look for products carrying the Healthier Choice Symbol (HCS) with this tagline, such as crisps/chips where each individually packaged portion is less than or equal to 100 calories. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_100_calories.jpg\" alt=\"Less Than 100\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Products carrying HCS with this tagline are ice cream products that are both lower in sugar compared to similar products in the same food category and less than or equal to 200 calories per portion. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_200_Calories.jpg\" alt=\"Less Than 200\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Choosing your snacks wisely can keep your energy levels up without piling on added calories. </span><br><span>Do you recall seeing this HCS label on the last snack you ate? </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1763866800,NULL,0,NULL,NULL,'push'),(68513,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1764471600,NULL,0,NULL,NULL,'push'),(68514,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1765076400,NULL,0,NULL,NULL,'push'),(68515,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1765681200,NULL,0,NULL,NULL,'push'),(68516,'Look out for \'whole\' in the ingredient list  ','<html><head></head><body><p><span>To identify wholegrain products, look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on the ingredient list. The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>There are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p><p><span>Another way is to look for products carrying the \"Higher in Wholegrains\" Healthier Choice Symbol, which contain more wholegrains compared to similar products from the same food category. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p> <a href=\"https://youtu.be/XmbV3VeDjM4?si=0Z4aQd2Wc-QqhPgp\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Go Wholegrain - Watch Youtube Video</a></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1766286000,NULL,0,NULL,NULL,'push'),(68517,'Know your portion size ','<html><head></head><body><p><span>You can find the amount of nutrition per portion on the nutrition information panel. The portion size is recommended by the manufacturer, and can vary between brands.</span></p><p><span>Be aware that the manufacturer\'s portion size might be smaller than yours, which means that even if a product looks healthy, if you have more than this amount, you may still end up consuming more calories, saturated fat, sugar or salt than you realize.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1766890800,NULL,0,NULL,NULL,'push'),(68518,'Let\'s Recap. ','<html><head></head><body><p>Shopping for healthy groceries allows you to cut back on sodium, find wholegrain products, reduce unhealthy oil and fats and limit sugar. One way is to understand food labels.<br><br>In the coming week, which method would you like to try out?</p><ul style=\"margin-top: 0;\"><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1767495600,NULL,0,NULL,NULL,'push'),(68519,'Hey Demond, did you manage to try out any of these grocery shopping methods?','<html><head></head><body><ul><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one method.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1767927600,NULL,0,NULL,NULL,'push'),(68520,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #1 Don\'t shop on an empty stomach</span><br><span>It\'s harder to resist buying higher-fat, higher-calorie snack items when you\'re hungry. Shop after you\'ve eaten a good meal. Drink some water or munch on a fruit before you shop.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1768100400,NULL,0,NULL,NULL,'push'),(68521,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Make a shopping list</span><br><span>Make a shopping list to reduce the urge to buy on impulse. Having a well-planned grocery list also saves time and helps you stick to your healthy eating plan.</span></p><span style=\"color: #FF98B7; font-weight: 500; \">Tips:</span><ul style=\" margin-top: 0;\"><li>Buy only what you will use, not because it is on promotion.</li><li>Resist \"buy one get one\" unless it is a staple.</li><li>Use store apps to compare prices.</li><li>Choose house-brands.</li><li>Select items with longer use-by date.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1768705200,NULL,0,NULL,NULL,'push'),(68522,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Go fresh </span><br>Choose fresh or frozen produce and less processed, wholesome foods (e.g. grains, nuts, eggs, herbs and spices) wherever possible.<br><br>Fresh produce are generally better than processed and ready-to-eat foods so that you know exactly what goes into your meal when you cook at home. They are also lower in fat, sugars and additives.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top:0;\"><li>Spend more time in the fresh produce section.</li><li>Limit your time in the aisles that stock snack food/candy and canned/processed foods.</li><li>Stick reminders on your fridge so that perishable fruit and vegetables are not forgotten in your fridge.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1769310000,NULL,0,NULL,NULL,'push'),(68523,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#4 Frozen or fresh </span><br>Frozen fruits and vegetables are flash-frozen to lock in their nutrients immediately after harvest. Fresh or frozen, fruit and vegetables are nutritious and healthier food choices. <br><br>Frozen produce is easy to keep in the freezer for when needed and will keep for far longer than fresh produce, helping to reduce food waste and save money. For out-of-season items, they can be cheaper than fresh produce.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\"margin-top:0\"><li>Buy enough to ensure everyone in your family have sufficient servings.</li><li>Eat a rainbow. Choose fruit and vegetables of different colours to get the maximum nutrients you need.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1769914800,NULL,0,NULL,NULL,'push'),(68524,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#5 Shop in season. Shop local.</span><br><span>Buy fruits and vegetables in season as they peak in flavour and nutrients, and are cheaper.</span></p><p><span>Most of our fruits and vegetables come from Malaysia, China, USA and Australia while local farms produce 12 percent of our leafy vegetables. Shorter time from source to market means fewer nutrients and flavour are lost in transit.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1770519600,NULL,0,NULL,NULL,'push'),(68525,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #6 Check food labels </span><br>If you have to buy processed or packaged foods, look out for the Healthier Choice Symbol (HCS). </p><p>The HCS can be found on the packaging of products such as convenience meals, sauces, drinks, snacks and breakfast cereals. Do you recall seeing the HCS on the items you bought recently? </p><p>Use the HCS to compare similar products so that you can choose the healthiest option. </p><p>You can also use the Nutrition Information Panel (NIP) to find out the amount of calories and nutrients you are getting out of each serving of food. <a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" target=\"_blank\" rel=\"noopener noreferrer\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Learn how to read the NIP at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1771124400,NULL,0,NULL,NULL,'push'),(68526,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#7 To buy organic produce or not</span><br><span>Numerous studies have been done over the decades but there is no clear conclusion that organic foods are healthier, safer or tastier than conventionally grown ones. Organic or not, make fruit and vegetables a part of your daily diet.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1771729200,NULL,0,NULL,NULL,'push'),(68527,'Let\'s Recap.','<html><head></head><body><p style=\"margin-bottom:0;\">We learned how to get our money\'s worth of healthy groceries.</p><ul style=\"margin-top:0;\"><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p><span>Which would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1772334000,NULL,0,NULL,NULL,'push'),(68528,'Hey Demond, did you manage to try out any of the dollar stretching ideas?','<html><head></head><body><ul><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1772766000,NULL,0,NULL,NULL,'push'),(68529,'Having a well-planned grocery list saves time and helps you stick to your healthy eating plan by making it easier for you to whip up healthier meals for yourself and your family.','<html><head></head><body><p><span>When shopping for healthy groceries, aim for balance, variety, and moderation.</span></p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">More tips:</span></p><ul style=\"padding-left:20px; margin-top:0;\"><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what you have first.</li><li>Then make a grocery list based on your meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to your list throughout the week, whenever you run out of something.</li><li>Buy only what you will use.</li><li>Stock up on pantry staples (e.g. rice, frozen meat/fish/vegetables, canned fish/beans, herbs).</li><li>Shop for perishables (e.g. fruit and vegetables) weekly.</li></ul><p><span>Is there another way to draw up a grocery list?</span></p><p><span>As a matter of fact, yes. But more of that next week.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1772938800,NULL,0,NULL,NULL,'push'),(68530,'Now let\'s get to your question on how to make an efficient grocery list in a few minutes.','<html><head></head><body><p>One way to do this is to organize your grocery list around the store layout. Base your list on how the same types of foods are grouped by aisle.</p><p><span> For Example,</span><br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Rice and Staples</span> aisle: <br>Healthier options include Brown rice, brown rice vermicelli, Whole wheat or whole-grain pasta.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cereals and Breakfast Foods</span> aisle: <br>Healthier options include Whole-grain or multigrain cereals, rolled oats or instant oatmeal, whole-grain cereal bars.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Bakery</span> aisle: <br>Healthier options include Whole wheat bread, pita pockets, Whole-grain flour tortillas.</p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span></p><ul style=\"margin-top:0; padding-left:20px;\"><li>Look for the words \"whole wheat\" or \"whole wheat flour\" as the first ingredient on the label.</li><li>Choose whole-grain breads that contain at least 3 to 4 grams of fiber and have fewer than 100 calories per slice.</li></ul><p>In the weeks to come, I can share more on how to use aisle layout to organise your grocery list.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1773543600,NULL,0,NULL,NULL,'push'),(68531,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Canned Goods</span> aisle:</span><br><span>Healthier options include Diced or whole peeled tomatoes, Beans/lentils/split peas, Tuna or salmon packed in spring water.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Limit consumption of canned foods as they tend to be higher in salt, sugar and fats.</li><li>Select products with the Healthier Choice Symbol.</li><li>When buying canned fruits, choose those that are packed in juice rather than syrup.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1774148400,NULL,0,NULL,NULL,'push'),(68532,'Organising grocery list by aisle','<html><head></head><body><p><em><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cooking Oils</span> aisle:</em><br><span>Healthier options include Canola oil, olive oil, peanut oil, rice bran oil, soybean oil, sesame oil.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Cooking oils have different smoke points.</li><li>For high-heat cooking (e.g. stir/deep frying), choose oils with higher smoke point such as peanut/rice bran/soybean oil.</li><li>Extra virgin olive oil has a relatively low smoke point of 199 °C and is not suitable for high-heat cooking.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1774753200,NULL,0,NULL,NULL,'push'),(68533,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Sauces and Condiments</span> aisle:</span><br><span>Many sauces, salad dressings and condiments are high in sodium, sugar and saturated fat.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>Opt for products that carry the \"Lower in Sodium\", \"Lower in Sugar\" or \"Lower in Saturated Fat\" Healthier Choice Symbol.</span><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Snacks and Crackers</span> aisle:</span><br><span>Healthier options include Whole-grain crackers, Dried fruit, nuts and seeds, peanut butter or almond butter, hummus, dark chocolates.</span></p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Drinks</span> aisle:</span><br><span>Healthier options include Unsweetened green and flavoured teas, Sparkling water.</span></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1775358000,NULL,0,NULL,NULL,'push'),(68534,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dairy and Eggs</span> aisle:<br>Healthier options include Skim or low-fat milk or soymilk, Fat-free or low-fat plain yogurt, Low-fat cheese, Eggs, Tofu, Butter or spread (a variety that doesn\'t contain hydrogenated oils).<br> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Meat and Seafood</span> aisle:<br>Healthier options include Skinless chicken breast, minced chicken, salmon, seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>If you buy red meat, choose the leanest cuts.</span><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Frozen Food</span> aisle:<br>Healthier options include Frozen fruit and vegetables, frozen meat/poultry/seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Use frozen vegetables to prepare soups, casseroles, and stews.</li><li>Low-fat frozen plain yogurt blended with frozen fruit makes a quick, healthy smoothie.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1775962800,NULL,0,NULL,NULL,'push'),(68535,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1776567600,NULL,0,NULL,NULL,'push'),(68536,'Let\'s Recap','<html><head></head><body><p><span>Having a well-planned grocery list saves time and helps you stick to your healthy eating plan.</span><br><br><span>Next time you go grocery shopping, which tips would you like to try out?</span></p><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1777172400,NULL,0,NULL,NULL,'push'),(68537,'Hey Demond, did you manage to try out any of the grocery shopping tips?','<html><head></head><body><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul><p>If you have tried, how was your experience?<br>If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1777604400,NULL,0,NULL,NULL,'push'),(68538,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1777777200,NULL,0,NULL,NULL,'push'),(68539,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Tropical Fruits</span><br>Choose <strong>mangosteens</strong> that can be pressed in slightly.<br><strong>Mangoes</strong> should be slightly soft with an intense fragrance.<br><strong>Dragonfruits</strong> are evenly pink with fresh-looking petals and a soft stem.<br>Pick yellow <strong>papayas</strong> that are slightly soft when pressed and is heavy for its size.<br>Ripe <strong>pineapples</strong> are yellow with a pleasant aroma at the stem end.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1778382000,NULL,0,NULL,NULL,'push'),(68540,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Citrus Fruits</span><br>Choose <strong>citrus fruits</strong> that are firm, bright-looking with finely-textured peel and give off a strong fragrance.<br>Choose <strong>grapefruits</strong> that are redder and pomelos with a yellow tinge.<br>Choose navel <strong>oranges</strong> if you like them to be sweet and seedless.<br><strong>Kiwis</strong> are slightly soft when ripe and have taut skin.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1778986800,NULL,0,NULL,NULL,'push'),(68541,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Melons</span><br>Ripe <strong>watermelons</strong> look dull, not shiny and have dried stem ends. Look for the cream-coloured patch on the skin where they rested on the ground before harvest — the deeper the colour, the better it is.<br>Netted melons such as <strong>rockmelons and cantaloupes</strong> give off an intense fragrance when they are fully ripe. <br>Baby-skinned <strong>honeydew</strong> does not wear a scent when they are ripe. Instead, look for a yellow tinge in their waxy exterior. The stem end of <strong>all melons</strong> can be pressed in gently when they are ripe.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1779591600,NULL,0,NULL,NULL,'push'),(68542,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Berries</span><br>Choose <strong>blueberries</strong> that are plump, brightly-coloured with a whitish bloom. Shake the container of blueberries gently. If the berries don’t move freely, they may be soft or damaged.<br>Buy <strong>strawberries</strong> that give off a strong scent, an indication that they are sweet and ripe.<br>Look for shiny and firm <strong>blackberries</strong>.<br><strong>Raspberries</strong> should be firm, plump and deeply-coloured.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"  margin-top: 0;\"><li>Store blackberries and raspberries in a single layer as they bruise easily</li><li>Berries only stay fresh for a few days, so eat them fast! If not, freeze them for frozen sweet treats</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1780196400,NULL,0,NULL,NULL,'push'),(68543,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Stone fruits (e.g. plum, peach, nectarine, apricot)</span><br><span>Select <strong>stone fruits</strong> with firm skin that is not wrinkled. Softer fruits are sweeter and juicier. Leave them to ripen before storing them in the fridge. A deeper colour is a hint of ripeness, especially around the stem end.</span></p><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Other fruits</span></span><br><span><strong>Apples</strong> and <strong>pears</strong> should be firm and smooth-skinned.</span><br><span>A ripe <strong>passionfruit</strong> is plump, heavy for its size and wrinkled.</span><br><span>Look for plump <strong>grapes</strong> with a whitish bloom and healthier brown stems that still hold the fruit firmly.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1780801200,NULL,0,NULL,NULL,'push'),(68544,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dark green vegetables</span><br><strong>Leafy vegetables</strong> such as spinach should have bright green leaves and tender, crisp stems.<br>Fresh <strong>broccolis</strong> have compact, green florets and undamaged stems.<br><strong>Lettuce</strong> leaves should be crisp and bright.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1781406000,NULL,0,NULL,NULL,'push'),(68545,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Red and orange vegetables</span><br><span>Pick slim, medium-sized <strong>carrots</strong> which are well-formed and bright.</span><br><span><strong>Capsicums</strong> and <strong>chilli</strong> should be firm, deeply-coloured and glossy.</span><br><span>Avoid <strong>sweet potatoes</strong> with stringed “beards” as they are older and less tasty! Pick small to medium-sized ones with even tones.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1782010800,NULL,0,NULL,NULL,'push'),(68546,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Beans and peas</span><br>Edible bean pods such as <strong>French beans, green beans and snow peas</strong> taste better when they are tender and crisp with smaller beans within them<br><strong>Sweet peas</strong> are firm and crisp; they should not bend<br><strong>Dried beans</strong> should be free from mould, insects or discolouration</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1782615600,NULL,0,NULL,NULL,'push'),(68547,'How to choose fresh vegetables?','<html><head></head><body><p><strong><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Starchy vegetables</span></strong><br>Choose <strong>potatoes</strong> which are firm and have fewer “eyes”. They should not have any sprouts.<br>Look for bright and plump <strong>corn</strong> kernels when buying an ear of corn.<br>A lighter <strong>yam</strong> (or taro) is a better pick as it has less water and more likely to be “powdery”. When choosing yam that has been cut, look for the ones with more red veins inside.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1783220400,NULL,0,NULL,NULL,'push'),(68548,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Others</span><br><span>A good <strong>cabbage</strong> should be firm or even hard.</span><br><span>Tender <strong>asparagus</strong> are bright green with tightly closed spears that have darker green or purplish tips.</span><br><span><strong>Cauliflower</strong> heads should be firm and compact with no brown spots.</span><br><span>If you are buying the longer variety of <strong>eggplant</strong> (or brinjal), hold it up and test if it is springy (and young) by flicking it gently.</span><br><span>Smaller and shorter <strong>lady’s fingers</strong> are younger and crisper.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1783825200,NULL,0,NULL,NULL,'push'),(68549,'Let\'s Recap.','<html><head></head><body><p><span>Thinking of your favourite fruit and vegetables, which method/s would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1784430000,NULL,0,NULL,NULL,'push'),(68550,'Hey Demond, did you manage to use any of the ideas to pick your favourite fruit and vegetables?','<html><head></head><body><p><span>If you have tried, how was your experience? <br>If not, you still have time to try at least one action. You can revisit the tips in the Notification Centre.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1784862000,NULL,0,NULL,NULL,'push'),(68551,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><span>Eating out is both fun and sociable. But it is easy to wind up overeating or indulging in a lot more fat, sugar, and salt than you normally would if you ate at home. In the weeks to come, I can share with you some clever tips to help you eat healthy at restaurants.</span></div><p style=\"margin-top:0px;margin-bottom:0px;\"><strong><em>Guide to healthy dining at restaurant</em></strong> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Plan ahead</span> <br><span>If you plan to eat out at your favourite restaurant, eat lighter meals through the rest of the day to allow for the additional calories you may indulge in.</span></p></body></html>','success','2025-08-26 16:15:52','2025-08-27 03:00:00',1,7579712,0,0,1756263600,NULL,0,NULL,NULL,'push'),(68552,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Be the first</em><br><span>Be the first to recommend a restaurant that serves healthier options or the first in your group to order a healthy dish. </span></div><div style=\"margin-bottom:20px;\"><span style=\" color: #FF98B7; font-style: italic; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\"><a href=\"https://www.healthhub.sg/live-healthy/5-healthier-cbd-lunchtime-dining-options\" style=\"color: #FF98B7; font-weight: 500; font-style: italic; text-decoration: underline; text-decoration-color: #FF98B7;\"> Which of your favourite restaurants offer healthier options? </a> </span></div><p style=\"margin-bottom:0px; margin-top:0px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Read the menu before you go</span><br><span>Choose your food before you get to the restaurant. It\'s easy to make unhealthy choices when hungry. The sight and smell of food and the food choices that others make can easily distract you from sticking to your health goals.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1756868400,NULL,0,NULL,NULL,'push'),(68553,'Guide to healthy dining at restaurant','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Choose dishes prepared using healthier methods </em><br><span>Avoid or limit items with names like crispy, deep-fried, in cream sauce, lemak, with coconut milk or in syrup as these tend to be higher in sugar and fat. </span></p><p><span>Ask the waiter or staff if you do not understand the fancy names of dishes. Dishes that are steamed, grilled, roasted or pan-fried are generally lower in calories. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1757473200,NULL,0,NULL,NULL,'push'),(68554,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order just enough</em><br><span>To control how much you eat, order just enough. You can always top up the food order later if needed. </span></div><div style=\"margin-bottom:20px;\"><span>Consider sharing food with someone else or ordering a half-portion if available. If you are going to a restaurant where you know the portions are huge, try ordering two appetizers instead of one main course. </span></div><p style=\"margin-top: 0px; margin-bottom:0px;\"><span>If there are extras, ask the waiter to bag it up if you do not like to see food wasted. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1758078000,NULL,0,NULL,NULL,'push'),(68555,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order a variety of dishes</span><br><span>Select a variety of items to make up a well-balanced meal. Include a staple, one or two vegetable side dishes, and one or two protein-rich items such as tofu, lentils, fish, chicken or lean meat. </span></div><div style=\"margin-bottom: 20px;\"><span>Consider starting with a salad, which not only adds greens to your meal but can also help to control your appetite. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Keep deep-fried or oily and fatty dishes to no more than one or two per meal. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1758682800,NULL,0,NULL,NULL,'push'),(68556,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Request for modifications </span><br><span>Don\'t be afraid to ask for modifications to your food.</span></div><div style=\"margin-bottom: 20px;\"><span>When placing your order, ask for your dishes to be prepared with less oil and sodium-containing seasonings. </span></div><p style=\"margin-bottom: 0px; margin-top:0px;\"><span>Considering swapping part of your meal, such as fries or potatoes, for extra vegetables or a salad. This can boost your fibre intake and reduce your calories consumed. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1759287600,NULL,0,NULL,NULL,'push'),(68557,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> Ask for sauces or dressings on the side </span><br> Sauces and dressings can be a hidden source of sugar, sodium and fat. Ask for sauces and dressings to be on the side so you can decide on the amount to add. </div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><a href=\"https://youtu.be/GXSO2-X4Cx4?si=w8JzuKUbLgvDTj0C\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Take less sauces and gravy - Watch Youtube Video</a></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1759892400,NULL,0,NULL,NULL,'push'),(68558,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span <span=\"\" style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Limit sugar-sweetened beverages and alcohol</span><br><span>For drinks, nothing beats water. Drinking water instead of sugar-sweetened drinks can help reduce your intake of calories and added sugar.</span></div><div style=\"margin-bottom: 20px;\"><span>If you would still like a beverage, opt for no-sugar or reduced-sugar drinks. For example, instead of a flavoured latte, go for a long black or a regular latte. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Alcoholic beverages are often high in calories with little nutritional value. If you must have a drink, limit yourself to 1 standard drink and opt for lower-calorie options like light beer and wine spritzers instead of sugary cocktails or mixed drinks. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1760497200,NULL,0,NULL,NULL,'push'),(68559,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">End the meal with fresh fruits instead of desserts</span><br><span>Craving a sweet treat at the end of your meal? Opt for a fresh fruit platter! It is a naturally sweet option that packs plenty of essential vitamins and minerals. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>If you still want to enjoy other desserts, select one with less sugar or syrup and cream. </span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1761102000,NULL,0,NULL,NULL,'push'),(68560,'Guide to healthy dining at restaurant','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Enjoy your favourite food in moderation</span><br><span>There will be times when you want to eat your favourite food and not worry about whether it is healthy or not. If you\'ve been eating healthily most of the time, go ahead and enjoy an occasional treat. Being flexible about your diet and food choices is linked with better overall health and weight management.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1761706800,NULL,0,NULL,NULL,'push'),(68561,'How do I avoid overeating when dining out?','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat mindfully</em><br><span>Slow down to give your body enough time to tell you that you are feeling full. Chew thoroughly and take the time to savour the aromas and flavours of your meal. Stop eating when you feel three-quarter full.</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1762311600,NULL,0,NULL,NULL,'push'),(68562,'What can I do to eat healthy at a fast-food restaurant?','<html><head></head><body><p><span>Fast food is convenient but tends to be high in calories, salt and fat. When consumed frequently and in excess, it may raise your risk of obesity, heart attack and other health issues.</span></p><div><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Resist upsizing the meal and drinks even though it may seem to make more monetary sense.</li><li>Select items that are grilled, not fried</li><li>Swap deep-fried sides (e.g. french fries or chips) for salad or steamed corn</li><li>If craving a sweet treat, opt for a cup of fresh fruits instead of ice-cream, sundae, or apple pie</li><li>Swap soft drinks for water</li><li>Ask for more vegetables in your burger</li></ul></div></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1762916400,NULL,0,NULL,NULL,'push'),(68563,'How do I control myself when dining at all-you-can-eat buffet?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat just enough </span><br><span>If you find yourself at all-you-can-eat buffet, select one favourite item from each section of the buffet line and eat no more than your regular portion. </span></p><p><span>Help yourself to small servings if you want to try the entire spread.</span></p><p><span>Eat slowly and take the time to savour your meal. Stop eating when you feel three-quarters full</span></p><p><span>If you are under pressure to keep eating to support your friends, eat slowly and steer the conversation away from your plate.</span></p><p><span>Spend more time socialising than eating</span></p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1763521200,NULL,0,NULL,NULL,'push'),(68564,'Choose one action to try out the next time you dine at a restaurant:','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1764126000,NULL,0,NULL,NULL,'push'),(68565,'Hey Demond, did you manage to try out any of these healthy dining tips? ','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-26 16:15:52','2025-08-26 16:15:52',0,7579712,0,0,1764558000,NULL,0,NULL,NULL,'push'),(68566,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1756609200,NULL,0,NULL,NULL,'push'),(68567,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Products high in fibre are also high in wholegrains.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,1,1757214000,NULL,0,NULL,'\n         <p><strong >Answer: FALSE</strong> </br>Just because a product is high in fibre does not necessarily mean that it is wholegrain.\n      Food enriched or added with wheat or bran may be high in fibre but they are not wholegrain unless wholewheat or other wholegrains are used in the product.</p>\n    ','push'),(68568,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Brown bread has wholegrains.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,1,1757818800,NULL,0,NULL,'\n    <p><strong >Answer: FALSE</strong> <br/>\n      Don\'t judge a grain by its colour. Just because the bread is brown doesn\'t mean it is made of wholegrains.\n      Some bread or crackers may be brown because ​molasses or caramel colouring may have been added.\n      Don\'t forget that many wholegrain products such as cereals are light in colour.</p>\n\n      <p >Also, wholegrain food are not always dry and gritty.\n      You will be pleasantly surprised that some wholegrains are light and flaky like cereal grains while some may be dense with an enjoyable nutty flavour.</p>\n    ','push'),(68569,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span>Unfortunately, the ingredient list and the nutrition information panel (NIP) will not tell you the amount of wholegrains present in the food. So how?</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the word \"whole\"</span><br><span>The ingredient list will show the wholegrain as an ingredient e.g. wholewheat flour or whole oats. Look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on a product to ensure it is a wholegrain product. </span></p><p><span>The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>But there are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1758423600,NULL,0,NULL,NULL,'push'),(68570,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the Healthier Choice Symbol</span><br><span>Products carrying the \"Higher in Wholegrains\" symbol contain more wholegrains compared to similar products from the same food category.</span><br><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></p><span>When you see this symbol, it means that the:</span><ul style=\"margin-top:0\"><li>Bread and breakfast cereals contains at least 25% wholegrains.</li><li>Brown rice or oats contains 100% wholegrains.</li><li>Vermicelli (bee hoon) contains at least 80% wholegrains.</li><li>Biscuits contains at least 30% wholegrains.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1759028400,NULL,0,NULL,NULL,'push'),(68571,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1759633200,NULL,0,NULL,NULL,'push'),(68572,'How to limit sugar when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Both HCS and Nutri-Grade Mark are the same.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,1,1760238000,NULL,0,NULL,'\n  <p><strong >Answer: FALSE</strong> <br />\n      The Nutri-Grade mark is a labelling scheme for beverages based on their sugar and saturated fat content.</br>Beverages which are Nutri-Grade “C” or “D” will be labelled with a Nutri-Grade mark, while labelling of beverages graded “A” or “B” is optional.</br>When having beverages, choose HCS, Nutri-Grade “A”/”B” beverages or simply water to control your sugar and saturated fat intake.</p>\n\n      <span style=\"color: #FF98B7;\">Tip:<br />\n  </span>Explore the list of drink options that are lower in sugar and saturated fats at\n      <a  href=\"https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">\n       https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home \n      </a></p>\n    ','push'),(68573,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1760842800,NULL,0,NULL,NULL,'push'),(68574,'How to tell if a food is healthy by reading the label?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Why is it important to read and understand food labels?</span><br><span>Reading food labels is the first step to making sure your kitchen is stocked with healthier food products.</span></p><p><span>The front, back and sides of a packaged product are filled with clues that tell you what the food contains and how much you are eating. These information can guide you in making healthier purchases to cut back on sodium, choose wholegrain products, reduce unhealthy oil and fats, and limit sugar.</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">What happens if we do not read food labels?</span><br><span>Without reading food labels, we might eat more calories than necessary, misjudge portion sizes and unknowingly consume high amounts of sugar, salt and unhealthy fats. We might also accidentally consume allergens or ingredients we are sensitive to, triggering undesired reactions. </span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Not everything has a food label</span><br><span>Fresh produce like fruit and vegetables that have not been peeled, cut or processed, herbs and spices, tea, coffee, flours and alcoholic drinks may not have a food label. </span></p><p><span>Aim to eat at least 2 servings of fruit and 2 servings of vegetables a day. On the other hand, try to limit alcohol intake as excessive alcohol consumption can ruin your health. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1761447600,NULL,0,NULL,NULL,'push'),(68575,'Tips for understanding food labels','<html><head></head><body><p><span>1. Read the ingredients list</span><br><span>2. Check the nutrition information panel</span><br><span>3. Be aware of the calorie count</span><br><span>4. Find out the type of fat, and how much</span><br><span>6. Spot hidden sugar</span><br><span>7. Beware of salt</span><br><span>8. Know your portion size</span></p><p><span>In the coming weeks, I can share more with you how to read and understand food labels.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1762052400,NULL,0,NULL,NULL,'push'),(68576,'Read the ingredients list','<html><head></head><body><p><span>Most packaged foods have an ingredients list on the back or side of the packet. Everything that goes into your food will be listed in weight order from biggest to the smallest. </span></p><p><span>If the first few ingredients you see are cream, butter, fatty meat or cheese, then you know that saturated fat makes up the largest proportion of the product. </span></p><p><span>If you spot sugars (white or brown), syrups or concentrated fruit juice at the top of the ingredients list, then you know that the product you are eyeing is loaded with sugar.</span></p><p><span>Ingredients that appear further down the list are present in the product in small quantities but that does not mean their impact is small. For example, vitamins and minerals are often added to foods like breakfast cereals and dairy in small quantities but can make a positive impact on your diets. </span></p><p><span>Similarly, even small amounts of salt can add up to our maximum of one teaspoon of salt a day.</span></p><p><span style=\"color: #FF98B7; font-style: italic; font-weight: 500;\">Beware:</span><br><span>Manufacturers may use less common names for ingredients such as sodium chloride in place of salt or maltose and fructose for sugars so people may think a certain ingredient is not in the ingredient list.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1762657200,NULL,0,NULL,NULL,'push'),(68577,'Check the nutritional information panel','<html><head></head><body><p>Use the nutrition information panel to find out the amount of nutrients you are getting out of the product.</p><p><strong>Servings per package </strong><br>The number of servings in a single container or packet. There could be more than one serving per package. </p><p><strong>Serving size </strong><br>This measure of a single-serving is defined by the manufacturer and varies from product to product. Be aware that the single serving indicated may be less than what you would typically eat.</p><p>A packet of potato chips may contain 160 calories per 30g serving and contain ten servings. This means if you eat the whole packet, you would have had a whopping 1,600 calories. </p><p><strong>Comparing values</strong><br>The most important ones to look out for are the BIG FOUR: total fat, saturated fat, sugar and salt. These can affect your weight and blood pressure, contributing to your risk of heart disease and stroke. </p><p>But you can also compare other nutrients to make healthier choices, including unsaturated fats (the good kind of fats), wholegrains and fibre.</p><p>When choosing between items look at the ‘per 100g’ or ‘per 100ml’ column as it offers a fairer comparison rather than serving size, which varies between products. </p><p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><br>Focus on the key nutrients that are important to you.<br>If you are on a diet, look at the energy or calorie values. For people with high blood pressure, zoom in on the sodium value or check the saturated fat and cholesterol amounts if you have high cholesterol.</p><p><a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Find out more at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1763262000,NULL,0,NULL,NULL,'push'),(68578,'Be aware of the calorie count ','<html><head></head><body><p><span>Calories (kcal) are a measure of how much energy is in a product. </span></p><p><span>Generally, women need around 1800 calories a day and men need around 2200 calories. But, the exact amounts needed by different persons will vary depending on their age, gender, height, weight and activity level.</span></p><p><span>Constant calorie counting isn\'t necessary but it\'s good to be aware of your calorie intake, especially if you want to maintain a healthy weight or lose a few extra pounds if necessary.</span></p><p><span>One way is to check the caloric content of the products you eat using \"per portion\" information, but do check how the manufacturer\'s portion compares with the portion you actually eat. For example, the manufacturer\'s portion might be two squares of chocolates but the actual amount of chocolates you eat might be much more.</span></p><p><span>Another way is to look for products carrying the Healthier Choice Symbol (HCS) with this tagline, such as crisps/chips where each individually packaged portion is less than or equal to 100 calories. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_100_calories.jpg\" alt=\"Less Than 100\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Products carrying HCS with this tagline are ice cream products that are both lower in sugar compared to similar products in the same food category and less than or equal to 200 calories per portion. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_200_Calories.jpg\" alt=\"Less Than 200\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Choosing your snacks wisely can keep your energy levels up without piling on added calories. </span><br><span>Do you recall seeing this HCS label on the last snack you ate? </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1763866800,NULL,0,NULL,NULL,'push'),(68579,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1764471600,NULL,0,NULL,NULL,'push'),(68580,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1765076400,NULL,0,NULL,NULL,'push'),(68581,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1765681200,NULL,0,NULL,NULL,'push'),(68582,'Look out for \'whole\' in the ingredient list  ','<html><head></head><body><p><span>To identify wholegrain products, look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on the ingredient list. The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>There are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p><p><span>Another way is to look for products carrying the \"Higher in Wholegrains\" Healthier Choice Symbol, which contain more wholegrains compared to similar products from the same food category. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p> <a href=\"https://youtu.be/XmbV3VeDjM4?si=0Z4aQd2Wc-QqhPgp\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Go Wholegrain - Watch Youtube Video</a></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1766286000,NULL,0,NULL,NULL,'push'),(68583,'Know your portion size ','<html><head></head><body><p><span>You can find the amount of nutrition per portion on the nutrition information panel. The portion size is recommended by the manufacturer, and can vary between brands.</span></p><p><span>Be aware that the manufacturer\'s portion size might be smaller than yours, which means that even if a product looks healthy, if you have more than this amount, you may still end up consuming more calories, saturated fat, sugar or salt than you realize.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1766890800,NULL,0,NULL,NULL,'push'),(68584,'Let\'s Recap. ','<html><head></head><body><p>Shopping for healthy groceries allows you to cut back on sodium, find wholegrain products, reduce unhealthy oil and fats and limit sugar. One way is to understand food labels.<br><br>In the coming week, which method would you like to try out?</p><ul style=\"margin-top: 0;\"><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1767495600,NULL,0,NULL,NULL,'push'),(68585,'Hey Vivien, did you manage to try out any of these grocery shopping methods?','<html><head></head><body><ul><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one method.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1767927600,NULL,0,NULL,NULL,'push'),(68586,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #1 Don\'t shop on an empty stomach</span><br><span>It\'s harder to resist buying higher-fat, higher-calorie snack items when you\'re hungry. Shop after you\'ve eaten a good meal. Drink some water or munch on a fruit before you shop.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1768100400,NULL,0,NULL,NULL,'push'),(68587,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Make a shopping list</span><br><span>Make a shopping list to reduce the urge to buy on impulse. Having a well-planned grocery list also saves time and helps you stick to your healthy eating plan.</span></p><span style=\"color: #FF98B7; font-weight: 500; \">Tips:</span><ul style=\" margin-top: 0;\"><li>Buy only what you will use, not because it is on promotion.</li><li>Resist \"buy one get one\" unless it is a staple.</li><li>Use store apps to compare prices.</li><li>Choose house-brands.</li><li>Select items with longer use-by date.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1768705200,NULL,0,NULL,NULL,'push'),(68588,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Go fresh </span><br>Choose fresh or frozen produce and less processed, wholesome foods (e.g. grains, nuts, eggs, herbs and spices) wherever possible.<br><br>Fresh produce are generally better than processed and ready-to-eat foods so that you know exactly what goes into your meal when you cook at home. They are also lower in fat, sugars and additives.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top:0;\"><li>Spend more time in the fresh produce section.</li><li>Limit your time in the aisles that stock snack food/candy and canned/processed foods.</li><li>Stick reminders on your fridge so that perishable fruit and vegetables are not forgotten in your fridge.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1769310000,NULL,0,NULL,NULL,'push'),(68589,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#4 Frozen or fresh </span><br>Frozen fruits and vegetables are flash-frozen to lock in their nutrients immediately after harvest. Fresh or frozen, fruit and vegetables are nutritious and healthier food choices. <br><br>Frozen produce is easy to keep in the freezer for when needed and will keep for far longer than fresh produce, helping to reduce food waste and save money. For out-of-season items, they can be cheaper than fresh produce.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\"margin-top:0\"><li>Buy enough to ensure everyone in your family have sufficient servings.</li><li>Eat a rainbow. Choose fruit and vegetables of different colours to get the maximum nutrients you need.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1769914800,NULL,0,NULL,NULL,'push'),(68590,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#5 Shop in season. Shop local.</span><br><span>Buy fruits and vegetables in season as they peak in flavour and nutrients, and are cheaper.</span></p><p><span>Most of our fruits and vegetables come from Malaysia, China, USA and Australia while local farms produce 12 percent of our leafy vegetables. Shorter time from source to market means fewer nutrients and flavour are lost in transit.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1770519600,NULL,0,NULL,NULL,'push'),(68591,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #6 Check food labels </span><br>If you have to buy processed or packaged foods, look out for the Healthier Choice Symbol (HCS). </p><p>The HCS can be found on the packaging of products such as convenience meals, sauces, drinks, snacks and breakfast cereals. Do you recall seeing the HCS on the items you bought recently? </p><p>Use the HCS to compare similar products so that you can choose the healthiest option. </p><p>You can also use the Nutrition Information Panel (NIP) to find out the amount of calories and nutrients you are getting out of each serving of food. <a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" target=\"_blank\" rel=\"noopener noreferrer\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Learn how to read the NIP at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1771124400,NULL,0,NULL,NULL,'push'),(68592,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#7 To buy organic produce or not</span><br><span>Numerous studies have been done over the decades but there is no clear conclusion that organic foods are healthier, safer or tastier than conventionally grown ones. Organic or not, make fruit and vegetables a part of your daily diet.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1771729200,NULL,0,NULL,NULL,'push'),(68593,'Let\'s Recap.','<html><head></head><body><p style=\"margin-bottom:0;\">We learned how to get our money\'s worth of healthy groceries.</p><ul style=\"margin-top:0;\"><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p><span>Which would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1772334000,NULL,0,NULL,NULL,'push'),(68594,'Hey Vivien, did you manage to try out any of the dollar stretching ideas?','<html><head></head><body><ul><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1772766000,NULL,0,NULL,NULL,'push'),(68595,'Having a well-planned grocery list saves time and helps you stick to your healthy eating plan by making it easier for you to whip up healthier meals for yourself and your family.','<html><head></head><body><p><span>When shopping for healthy groceries, aim for balance, variety, and moderation.</span></p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">More tips:</span></p><ul style=\"padding-left:20px; margin-top:0;\"><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what you have first.</li><li>Then make a grocery list based on your meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to your list throughout the week, whenever you run out of something.</li><li>Buy only what you will use.</li><li>Stock up on pantry staples (e.g. rice, frozen meat/fish/vegetables, canned fish/beans, herbs).</li><li>Shop for perishables (e.g. fruit and vegetables) weekly.</li></ul><p><span>Is there another way to draw up a grocery list?</span></p><p><span>As a matter of fact, yes. But more of that next week.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1772938800,NULL,0,NULL,NULL,'push'),(68596,'Now let\'s get to your question on how to make an efficient grocery list in a few minutes.','<html><head></head><body><p>One way to do this is to organize your grocery list around the store layout. Base your list on how the same types of foods are grouped by aisle.</p><p><span> For Example,</span><br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Rice and Staples</span> aisle: <br>Healthier options include Brown rice, brown rice vermicelli, Whole wheat or whole-grain pasta.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cereals and Breakfast Foods</span> aisle: <br>Healthier options include Whole-grain or multigrain cereals, rolled oats or instant oatmeal, whole-grain cereal bars.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Bakery</span> aisle: <br>Healthier options include Whole wheat bread, pita pockets, Whole-grain flour tortillas.</p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span></p><ul style=\"margin-top:0; padding-left:20px;\"><li>Look for the words \"whole wheat\" or \"whole wheat flour\" as the first ingredient on the label.</li><li>Choose whole-grain breads that contain at least 3 to 4 grams of fiber and have fewer than 100 calories per slice.</li></ul><p>In the weeks to come, I can share more on how to use aisle layout to organise your grocery list.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1773543600,NULL,0,NULL,NULL,'push'),(68597,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Canned Goods</span> aisle:</span><br><span>Healthier options include Diced or whole peeled tomatoes, Beans/lentils/split peas, Tuna or salmon packed in spring water.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Limit consumption of canned foods as they tend to be higher in salt, sugar and fats.</li><li>Select products with the Healthier Choice Symbol.</li><li>When buying canned fruits, choose those that are packed in juice rather than syrup.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1774148400,NULL,0,NULL,NULL,'push'),(68598,'Organising grocery list by aisle','<html><head></head><body><p><em><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cooking Oils</span> aisle:</em><br><span>Healthier options include Canola oil, olive oil, peanut oil, rice bran oil, soybean oil, sesame oil.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Cooking oils have different smoke points.</li><li>For high-heat cooking (e.g. stir/deep frying), choose oils with higher smoke point such as peanut/rice bran/soybean oil.</li><li>Extra virgin olive oil has a relatively low smoke point of 199 °C and is not suitable for high-heat cooking.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1774753200,NULL,0,NULL,NULL,'push'),(68599,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Sauces and Condiments</span> aisle:</span><br><span>Many sauces, salad dressings and condiments are high in sodium, sugar and saturated fat.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>Opt for products that carry the \"Lower in Sodium\", \"Lower in Sugar\" or \"Lower in Saturated Fat\" Healthier Choice Symbol.</span><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Snacks and Crackers</span> aisle:</span><br><span>Healthier options include Whole-grain crackers, Dried fruit, nuts and seeds, peanut butter or almond butter, hummus, dark chocolates.</span></p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Drinks</span> aisle:</span><br><span>Healthier options include Unsweetened green and flavoured teas, Sparkling water.</span></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1775358000,NULL,0,NULL,NULL,'push'),(68600,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dairy and Eggs</span> aisle:<br>Healthier options include Skim or low-fat milk or soymilk, Fat-free or low-fat plain yogurt, Low-fat cheese, Eggs, Tofu, Butter or spread (a variety that doesn\'t contain hydrogenated oils).<br> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Meat and Seafood</span> aisle:<br>Healthier options include Skinless chicken breast, minced chicken, salmon, seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>If you buy red meat, choose the leanest cuts.</span><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Frozen Food</span> aisle:<br>Healthier options include Frozen fruit and vegetables, frozen meat/poultry/seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Use frozen vegetables to prepare soups, casseroles, and stews.</li><li>Low-fat frozen plain yogurt blended with frozen fruit makes a quick, healthy smoothie.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1775962800,NULL,0,NULL,NULL,'push'),(68601,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1776567600,NULL,0,NULL,NULL,'push'),(68602,'Let\'s Recap','<html><head></head><body><p><span>Having a well-planned grocery list saves time and helps you stick to your healthy eating plan.</span><br><br><span>Next time you go grocery shopping, which tips would you like to try out?</span></p><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1777172400,NULL,0,NULL,NULL,'push'),(68603,'Hey Vivien, did you manage to try out any of the grocery shopping tips?','<html><head></head><body><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul><p>If you have tried, how was your experience?<br>If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1777604400,NULL,0,NULL,NULL,'push'),(68604,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1777777200,NULL,0,NULL,NULL,'push'),(68605,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Tropical Fruits</span><br>Choose <strong>mangosteens</strong> that can be pressed in slightly.<br><strong>Mangoes</strong> should be slightly soft with an intense fragrance.<br><strong>Dragonfruits</strong> are evenly pink with fresh-looking petals and a soft stem.<br>Pick yellow <strong>papayas</strong> that are slightly soft when pressed and is heavy for its size.<br>Ripe <strong>pineapples</strong> are yellow with a pleasant aroma at the stem end.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1778382000,NULL,0,NULL,NULL,'push'),(68606,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Citrus Fruits</span><br>Choose <strong>citrus fruits</strong> that are firm, bright-looking with finely-textured peel and give off a strong fragrance.<br>Choose <strong>grapefruits</strong> that are redder and pomelos with a yellow tinge.<br>Choose navel <strong>oranges</strong> if you like them to be sweet and seedless.<br><strong>Kiwis</strong> are slightly soft when ripe and have taut skin.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1778986800,NULL,0,NULL,NULL,'push'),(68607,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Melons</span><br>Ripe <strong>watermelons</strong> look dull, not shiny and have dried stem ends. Look for the cream-coloured patch on the skin where they rested on the ground before harvest — the deeper the colour, the better it is.<br>Netted melons such as <strong>rockmelons and cantaloupes</strong> give off an intense fragrance when they are fully ripe. <br>Baby-skinned <strong>honeydew</strong> does not wear a scent when they are ripe. Instead, look for a yellow tinge in their waxy exterior. The stem end of <strong>all melons</strong> can be pressed in gently when they are ripe.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1779591600,NULL,0,NULL,NULL,'push'),(68608,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Berries</span><br>Choose <strong>blueberries</strong> that are plump, brightly-coloured with a whitish bloom. Shake the container of blueberries gently. If the berries don’t move freely, they may be soft or damaged.<br>Buy <strong>strawberries</strong> that give off a strong scent, an indication that they are sweet and ripe.<br>Look for shiny and firm <strong>blackberries</strong>.<br><strong>Raspberries</strong> should be firm, plump and deeply-coloured.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"  margin-top: 0;\"><li>Store blackberries and raspberries in a single layer as they bruise easily</li><li>Berries only stay fresh for a few days, so eat them fast! If not, freeze them for frozen sweet treats</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1780196400,NULL,0,NULL,NULL,'push'),(68609,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Stone fruits (e.g. plum, peach, nectarine, apricot)</span><br><span>Select <strong>stone fruits</strong> with firm skin that is not wrinkled. Softer fruits are sweeter and juicier. Leave them to ripen before storing them in the fridge. A deeper colour is a hint of ripeness, especially around the stem end.</span></p><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Other fruits</span></span><br><span><strong>Apples</strong> and <strong>pears</strong> should be firm and smooth-skinned.</span><br><span>A ripe <strong>passionfruit</strong> is plump, heavy for its size and wrinkled.</span><br><span>Look for plump <strong>grapes</strong> with a whitish bloom and healthier brown stems that still hold the fruit firmly.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1780801200,NULL,0,NULL,NULL,'push'),(68610,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dark green vegetables</span><br><strong>Leafy vegetables</strong> such as spinach should have bright green leaves and tender, crisp stems.<br>Fresh <strong>broccolis</strong> have compact, green florets and undamaged stems.<br><strong>Lettuce</strong> leaves should be crisp and bright.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1781406000,NULL,0,NULL,NULL,'push'),(68611,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Red and orange vegetables</span><br><span>Pick slim, medium-sized <strong>carrots</strong> which are well-formed and bright.</span><br><span><strong>Capsicums</strong> and <strong>chilli</strong> should be firm, deeply-coloured and glossy.</span><br><span>Avoid <strong>sweet potatoes</strong> with stringed “beards” as they are older and less tasty! Pick small to medium-sized ones with even tones.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1782010800,NULL,0,NULL,NULL,'push'),(68612,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Beans and peas</span><br>Edible bean pods such as <strong>French beans, green beans and snow peas</strong> taste better when they are tender and crisp with smaller beans within them<br><strong>Sweet peas</strong> are firm and crisp; they should not bend<br><strong>Dried beans</strong> should be free from mould, insects or discolouration</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1782615600,NULL,0,NULL,NULL,'push'),(68613,'How to choose fresh vegetables?','<html><head></head><body><p><strong><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Starchy vegetables</span></strong><br>Choose <strong>potatoes</strong> which are firm and have fewer “eyes”. They should not have any sprouts.<br>Look for bright and plump <strong>corn</strong> kernels when buying an ear of corn.<br>A lighter <strong>yam</strong> (or taro) is a better pick as it has less water and more likely to be “powdery”. When choosing yam that has been cut, look for the ones with more red veins inside.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1783220400,NULL,0,NULL,NULL,'push'),(68614,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Others</span><br><span>A good <strong>cabbage</strong> should be firm or even hard.</span><br><span>Tender <strong>asparagus</strong> are bright green with tightly closed spears that have darker green or purplish tips.</span><br><span><strong>Cauliflower</strong> heads should be firm and compact with no brown spots.</span><br><span>If you are buying the longer variety of <strong>eggplant</strong> (or brinjal), hold it up and test if it is springy (and young) by flicking it gently.</span><br><span>Smaller and shorter <strong>lady’s fingers</strong> are younger and crisper.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1783825200,NULL,0,NULL,NULL,'push'),(68615,'Let\'s Recap.','<html><head></head><body><p><span>Thinking of your favourite fruit and vegetables, which method/s would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1784430000,NULL,0,NULL,NULL,'push'),(68616,'Hey Vivien, did you manage to use any of the ideas to pick your favourite fruit and vegetables?','<html><head></head><body><p><span>If you have tried, how was your experience? <br>If not, you still have time to try at least one action. You can revisit the tips in the Notification Centre.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1784862000,NULL,0,NULL,NULL,'push'),(68617,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><span>Eating out is both fun and sociable. But it is easy to wind up overeating or indulging in a lot more fat, sugar, and salt than you normally would if you ate at home. In the weeks to come, I can share with you some clever tips to help you eat healthy at restaurants.</span></div><p style=\"margin-top:0px;margin-bottom:0px;\"><strong><em>Guide to healthy dining at restaurant</em></strong> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Plan ahead</span> <br><span>If you plan to eat out at your favourite restaurant, eat lighter meals through the rest of the day to allow for the additional calories you may indulge in.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1756868400,NULL,0,NULL,NULL,'push'),(68618,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Be the first</em><br><span>Be the first to recommend a restaurant that serves healthier options or the first in your group to order a healthy dish. </span></div><div style=\"margin-bottom:20px;\"><span style=\" color: #FF98B7; font-style: italic; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\"><a href=\"https://www.healthhub.sg/live-healthy/5-healthier-cbd-lunchtime-dining-options\" style=\"color: #FF98B7; font-weight: 500; font-style: italic; text-decoration: underline; text-decoration-color: #FF98B7;\"> Which of your favourite restaurants offer healthier options? </a> </span></div><p style=\"margin-bottom:0px; margin-top:0px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Read the menu before you go</span><br><span>Choose your food before you get to the restaurant. It\'s easy to make unhealthy choices when hungry. The sight and smell of food and the food choices that others make can easily distract you from sticking to your health goals.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1757473200,NULL,0,NULL,NULL,'push'),(68619,'Guide to healthy dining at restaurant','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Choose dishes prepared using healthier methods </em><br><span>Avoid or limit items with names like crispy, deep-fried, in cream sauce, lemak, with coconut milk or in syrup as these tend to be higher in sugar and fat. </span></p><p><span>Ask the waiter or staff if you do not understand the fancy names of dishes. Dishes that are steamed, grilled, roasted or pan-fried are generally lower in calories. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1758078000,NULL,0,NULL,NULL,'push'),(68620,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order just enough</em><br><span>To control how much you eat, order just enough. You can always top up the food order later if needed. </span></div><div style=\"margin-bottom:20px;\"><span>Consider sharing food with someone else or ordering a half-portion if available. If you are going to a restaurant where you know the portions are huge, try ordering two appetizers instead of one main course. </span></div><p style=\"margin-top: 0px; margin-bottom:0px;\"><span>If there are extras, ask the waiter to bag it up if you do not like to see food wasted. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1758682800,NULL,0,NULL,NULL,'push'),(68621,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order a variety of dishes</span><br><span>Select a variety of items to make up a well-balanced meal. Include a staple, one or two vegetable side dishes, and one or two protein-rich items such as tofu, lentils, fish, chicken or lean meat. </span></div><div style=\"margin-bottom: 20px;\"><span>Consider starting with a salad, which not only adds greens to your meal but can also help to control your appetite. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Keep deep-fried or oily and fatty dishes to no more than one or two per meal. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1759287600,NULL,0,NULL,NULL,'push'),(68622,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Request for modifications </span><br><span>Don\'t be afraid to ask for modifications to your food.</span></div><div style=\"margin-bottom: 20px;\"><span>When placing your order, ask for your dishes to be prepared with less oil and sodium-containing seasonings. </span></div><p style=\"margin-bottom: 0px; margin-top:0px;\"><span>Considering swapping part of your meal, such as fries or potatoes, for extra vegetables or a salad. This can boost your fibre intake and reduce your calories consumed. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1759892400,NULL,0,NULL,NULL,'push'),(68623,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> Ask for sauces or dressings on the side </span><br> Sauces and dressings can be a hidden source of sugar, sodium and fat. Ask for sauces and dressings to be on the side so you can decide on the amount to add. </div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><a href=\"https://youtu.be/GXSO2-X4Cx4?si=w8JzuKUbLgvDTj0C\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Take less sauces and gravy - Watch Youtube Video</a></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1760497200,NULL,0,NULL,NULL,'push'),(68624,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span <span=\"\" style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Limit sugar-sweetened beverages and alcohol</span><br><span>For drinks, nothing beats water. Drinking water instead of sugar-sweetened drinks can help reduce your intake of calories and added sugar.</span></div><div style=\"margin-bottom: 20px;\"><span>If you would still like a beverage, opt for no-sugar or reduced-sugar drinks. For example, instead of a flavoured latte, go for a long black or a regular latte. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Alcoholic beverages are often high in calories with little nutritional value. If you must have a drink, limit yourself to 1 standard drink and opt for lower-calorie options like light beer and wine spritzers instead of sugary cocktails or mixed drinks. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1761102000,NULL,0,NULL,NULL,'push'),(68625,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">End the meal with fresh fruits instead of desserts</span><br><span>Craving a sweet treat at the end of your meal? Opt for a fresh fruit platter! It is a naturally sweet option that packs plenty of essential vitamins and minerals. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>If you still want to enjoy other desserts, select one with less sugar or syrup and cream. </span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1761706800,NULL,0,NULL,NULL,'push'),(68626,'Guide to healthy dining at restaurant','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Enjoy your favourite food in moderation</span><br><span>There will be times when you want to eat your favourite food and not worry about whether it is healthy or not. If you\'ve been eating healthily most of the time, go ahead and enjoy an occasional treat. Being flexible about your diet and food choices is linked with better overall health and weight management.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1762311600,NULL,0,NULL,NULL,'push'),(68627,'How do I avoid overeating when dining out?','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat mindfully</em><br><span>Slow down to give your body enough time to tell you that you are feeling full. Chew thoroughly and take the time to savour the aromas and flavours of your meal. Stop eating when you feel three-quarter full.</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1762916400,NULL,0,NULL,NULL,'push'),(68628,'What can I do to eat healthy at a fast-food restaurant?','<html><head></head><body><p><span>Fast food is convenient but tends to be high in calories, salt and fat. When consumed frequently and in excess, it may raise your risk of obesity, heart attack and other health issues.</span></p><div><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Resist upsizing the meal and drinks even though it may seem to make more monetary sense.</li><li>Select items that are grilled, not fried</li><li>Swap deep-fried sides (e.g. french fries or chips) for salad or steamed corn</li><li>If craving a sweet treat, opt for a cup of fresh fruits instead of ice-cream, sundae, or apple pie</li><li>Swap soft drinks for water</li><li>Ask for more vegetables in your burger</li></ul></div></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1763521200,NULL,0,NULL,NULL,'push'),(68629,'How do I control myself when dining at all-you-can-eat buffet?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat just enough </span><br><span>If you find yourself at all-you-can-eat buffet, select one favourite item from each section of the buffet line and eat no more than your regular portion. </span></p><p><span>Help yourself to small servings if you want to try the entire spread.</span></p><p><span>Eat slowly and take the time to savour your meal. Stop eating when you feel three-quarters full</span></p><p><span>If you are under pressure to keep eating to support your friends, eat slowly and steer the conversation away from your plate.</span></p><p><span>Spend more time socialising than eating</span></p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1764126000,NULL,0,NULL,NULL,'push'),(68630,'Choose one action to try out the next time you dine at a restaurant:','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1764730800,NULL,0,NULL,NULL,'push'),(68631,'Hey Vivien, did you manage to try out any of these healthy dining tips? ','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-27 05:01:07','2025-08-27 05:01:07',0,7511250,0,0,1765162800,NULL,0,NULL,NULL,'push'),(68632,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1756609200,NULL,0,NULL,NULL,'push'),(68633,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Products high in fibre are also high in wholegrains.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,1,1757214000,NULL,0,NULL,'\n         <p><strong >Answer: FALSE</strong> </br>Just because a product is high in fibre does not necessarily mean that it is wholegrain.\n      Food enriched or added with wheat or bran may be high in fibre but they are not wholegrain unless wholewheat or other wholegrains are used in the product.</p>\n    ','push'),(68634,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Brown bread has wholegrains.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,1,1757818800,NULL,0,NULL,'\n    <p><strong >Answer: FALSE</strong> <br/>\n      Don\'t judge a grain by its colour. Just because the bread is brown doesn\'t mean it is made of wholegrains.\n      Some bread or crackers may be brown because ​molasses or caramel colouring may have been added.\n      Don\'t forget that many wholegrain products such as cereals are light in colour.</p>\n\n      <p >Also, wholegrain food are not always dry and gritty.\n      You will be pleasantly surprised that some wholegrains are light and flaky like cereal grains while some may be dense with an enjoyable nutty flavour.</p>\n    ','push'),(68635,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span>Unfortunately, the ingredient list and the nutrition information panel (NIP) will not tell you the amount of wholegrains present in the food. So how?</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the word \"whole\"</span><br><span>The ingredient list will show the wholegrain as an ingredient e.g. wholewheat flour or whole oats. Look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on a product to ensure it is a wholegrain product. </span></p><p><span>The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>But there are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1758423600,NULL,0,NULL,NULL,'push'),(68636,'How to identify wholegrain products when shopping for groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Look out for the Healthier Choice Symbol</span><br><span>Products carrying the \"Higher in Wholegrains\" symbol contain more wholegrains compared to similar products from the same food category.</span><br><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></p><span>When you see this symbol, it means that the:</span><ul style=\"margin-top:0\"><li>Bread and breakfast cereals contains at least 25% wholegrains.</li><li>Brown rice or oats contains 100% wholegrains.</li><li>Vermicelli (bee hoon) contains at least 80% wholegrains.</li><li>Biscuits contains at least 30% wholegrains.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1759028400,NULL,0,NULL,NULL,'push'),(68637,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1759633200,NULL,0,NULL,NULL,'push'),(68638,'How to limit sugar when shopping for groceries?','<html><head></head><body><p><span style=\"color: #FF98B7; font-weight: 500;\">Quiz:</span><br>Both HCS and Nutri-Grade Mark are the same.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,1,1760238000,NULL,0,NULL,'\n  <p><strong >Answer: FALSE</strong> <br />\n      The Nutri-Grade mark is a labelling scheme for beverages based on their sugar and saturated fat content.</br>Beverages which are Nutri-Grade “C” or “D” will be labelled with a Nutri-Grade mark, while labelling of beverages graded “A” or “B” is optional.</br>When having beverages, choose HCS, Nutri-Grade “A”/”B” beverages or simply water to control your sugar and saturated fat intake.</p>\n\n      <span style=\"color: #FF98B7;\">Tip:<br />\n  </span>Explore the list of drink options that are lower in sugar and saturated fats at\n      <a  href=\"https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">\n       https://www.healthhub.sg/programmes/nutrition-hub/nutri-grade-a-and-b-drinks#home \n      </a></p>\n    ','push'),(68639,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1760842800,NULL,0,NULL,NULL,'push'),(68640,'How to tell if a food is healthy by reading the label?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Why is it important to read and understand food labels?</span><br><span>Reading food labels is the first step to making sure your kitchen is stocked with healthier food products.</span></p><p><span>The front, back and sides of a packaged product are filled with clues that tell you what the food contains and how much you are eating. These information can guide you in making healthier purchases to cut back on sodium, choose wholegrain products, reduce unhealthy oil and fats, and limit sugar.</span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">What happens if we do not read food labels?</span><br><span>Without reading food labels, we might eat more calories than necessary, misjudge portion sizes and unknowingly consume high amounts of sugar, salt and unhealthy fats. We might also accidentally consume allergens or ingredients we are sensitive to, triggering undesired reactions. </span></p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Not everything has a food label</span><br><span>Fresh produce like fruit and vegetables that have not been peeled, cut or processed, herbs and spices, tea, coffee, flours and alcoholic drinks may not have a food label. </span></p><p><span>Aim to eat at least 2 servings of fruit and 2 servings of vegetables a day. On the other hand, try to limit alcohol intake as excessive alcohol consumption can ruin your health. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1761447600,NULL,0,NULL,NULL,'push'),(68641,'Tips for understanding food labels','<html><head></head><body><p><span>1. Read the ingredients list</span><br><span>2. Check the nutrition information panel</span><br><span>3. Be aware of the calorie count</span><br><span>4. Find out the type of fat, and how much</span><br><span>6. Spot hidden sugar</span><br><span>7. Beware of salt</span><br><span>8. Know your portion size</span></p><p><span>In the coming weeks, I can share more with you how to read and understand food labels.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1762052400,NULL,0,NULL,NULL,'push'),(68642,'Read the ingredients list','<html><head></head><body><p><span>Most packaged foods have an ingredients list on the back or side of the packet. Everything that goes into your food will be listed in weight order from biggest to the smallest. </span></p><p><span>If the first few ingredients you see are cream, butter, fatty meat or cheese, then you know that saturated fat makes up the largest proportion of the product. </span></p><p><span>If you spot sugars (white or brown), syrups or concentrated fruit juice at the top of the ingredients list, then you know that the product you are eyeing is loaded with sugar.</span></p><p><span>Ingredients that appear further down the list are present in the product in small quantities but that does not mean their impact is small. For example, vitamins and minerals are often added to foods like breakfast cereals and dairy in small quantities but can make a positive impact on your diets. </span></p><p><span>Similarly, even small amounts of salt can add up to our maximum of one teaspoon of salt a day.</span></p><p><span style=\"color: #FF98B7; font-style: italic; font-weight: 500;\">Beware:</span><br><span>Manufacturers may use less common names for ingredients such as sodium chloride in place of salt or maltose and fructose for sugars so people may think a certain ingredient is not in the ingredient list.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1762657200,NULL,0,NULL,NULL,'push'),(68643,'Check the nutritional information panel','<html><head></head><body><p>Use the nutrition information panel to find out the amount of nutrients you are getting out of the product.</p><p><strong>Servings per package </strong><br>The number of servings in a single container or packet. There could be more than one serving per package. </p><p><strong>Serving size </strong><br>This measure of a single-serving is defined by the manufacturer and varies from product to product. Be aware that the single serving indicated may be less than what you would typically eat.</p><p>A packet of potato chips may contain 160 calories per 30g serving and contain ten servings. This means if you eat the whole packet, you would have had a whopping 1,600 calories. </p><p><strong>Comparing values</strong><br>The most important ones to look out for are the BIG FOUR: total fat, saturated fat, sugar and salt. These can affect your weight and blood pressure, contributing to your risk of heart disease and stroke. </p><p>But you can also compare other nutrients to make healthier choices, including unsaturated fats (the good kind of fats), wholegrains and fibre.</p><p>When choosing between items look at the ‘per 100g’ or ‘per 100ml’ column as it offers a fairer comparison rather than serving size, which varies between products. </p><p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><br>Focus on the key nutrients that are important to you.<br>If you are on a diet, look at the energy or calorie values. For people with high blood pressure, zoom in on the sodium value or check the saturated fat and cholesterol amounts if you have high cholesterol.</p><p><a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Find out more at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1763262000,NULL,0,NULL,NULL,'push'),(68644,'Be aware of the calorie count ','<html><head></head><body><p><span>Calories (kcal) are a measure of how much energy is in a product. </span></p><p><span>Generally, women need around 1800 calories a day and men need around 2200 calories. But, the exact amounts needed by different persons will vary depending on their age, gender, height, weight and activity level.</span></p><p><span>Constant calorie counting isn\'t necessary but it\'s good to be aware of your calorie intake, especially if you want to maintain a healthy weight or lose a few extra pounds if necessary.</span></p><p><span>One way is to check the caloric content of the products you eat using \"per portion\" information, but do check how the manufacturer\'s portion compares with the portion you actually eat. For example, the manufacturer\'s portion might be two squares of chocolates but the actual amount of chocolates you eat might be much more.</span></p><p><span>Another way is to look for products carrying the Healthier Choice Symbol (HCS) with this tagline, such as crisps/chips where each individually packaged portion is less than or equal to 100 calories. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_100_calories.jpg\" alt=\"Less Than 100\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Products carrying HCS with this tagline are ice cream products that are both lower in sugar compared to similar products in the same food category and less than or equal to 200 calories per portion. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Less_than_200_Calories.jpg\" alt=\"Less Than 200\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>Choosing your snacks wisely can keep your energy levels up without piling on added calories. </span><br><span>Do you recall seeing this HCS label on the last snack you ate? </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1763866800,NULL,0,NULL,NULL,'push'),(68645,'Read food labels to find out the type of fat and how much','<html><head></head><body><p><span>Fat has a lot of calories. But not all fats are created equal.</span></p><p><span>Monounsaturated and polyunsaturated fats, found in foods like avocado, nuts, seeds, oily fish and certain vegetable oils (e.g. corn, soya, olive oil), are better for your heart health.</span></p><p><span>On the other hand, saturated fats can increase your cholesterol and put you at greater risk of heart disease.</span></p><p><span>How then do you find out the type of fat and how much?</span></p><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#1 Check the first three ingredients on the ingredient list</span><br><span>If you see hydrogenated or partially hydrogenated fats, oils or shortening of animal or vegetable origin, these products (e.g. butter, full fat milk, fatty meats, pastry, biscuits, cakes) are likely to be high in saturated and trans fat.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Read the Nutrition Information Panel</span><br><span>Use the Nutrition Information Panel to compare the amount of total fat and saturated fat in food products.</span></p></div><div><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Look out for the Healthier Choice Symbol</span><br><span>Products carrying the Healthier Choice Symbol with this tagline contain at least 25% less saturated fat compared to similar products in the same food category.</span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Saturated_Fat.jpg\" alt=\"Low in Saturated Fat\" style=\"width: 100%; max-width: 400px; height: 200px; object-fit: contain;\"></div><div><p><span style=\"color: #FF98B7; font-weight: 500; margin-top:0;\">Tip: Beware of reduced-fat claims</span><br><span>Just because a product is marketed as \"reduced-fat\" or \"low-fat\" doesn\'t necessarily make it a healthier option.</span><br><span>Sometimes manufacturers replace fat with sugar or salt, which isn\'t a healthier replacement. So read the nutritional information to compare the original and reduced-fat version of the product. If there is not much difference, you might be better off eating a smaller amount of the original product.</span></p></div></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1764471600,NULL,0,NULL,NULL,'push'),(68646,'Spot hidden sugar (including naturally occuring sugars) in food labels','<html><head></head><body><p><span>Sugars are added to food for many reasons, including for preserving and flavouring. However, added sugars provide calories with little nutritional value, and have been linked to a greater risk of developing obesity, diabetes and heart disease. </span></p><p><span>Look out for added sugars in the ingredient list and aim to limit their intake. Beware, sugar can sometimes be disguised under other names: honey, syrup, nectar, molasses, fruit juice concentrate, anything ending in \'ose\' such as fructose, glucose, dextrose and maltose.</span></p><p><span>If limiting sugar intake is important for you, know that products carrying the Healthier Choice Symbol (HCS) with this tagline will have at least 25% less sugar compared to drinks without the symbol. But really, nothing beats water to quench your thirst. </span></p><p><span>Examples of foods carrying the HCS with this tagline include packet drinks such as chrysanthemum tea, Asian drinks, isotonic drinks, carbonated drinks, cultured milk products and fruit juice. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sugar.jpg\" alt=\"Lower in Sugar\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p><span>The Nutri-Grade mark also provides an indication of the amount of sugar and saturated fat in packaged and freshly prepared beverages. Go for drinks labelled Nutri-Grade \"A\" or \"B\", which have lower sugar and saturated fat content.</span></p><img src=\"https://static.connectedlife.io/assets/images/nutri_grade.png\" alt=\"Zero Sugar\" style=\"width: 100%; max-width: 300px; height: 150px;object-fit: contain;\"><p><a href=\"https://youtu.be/WXBPJUATcFs?si=HUpe2qtoI_VkO4VU\" rel=\"noopener noreferrer\" target=\"_blank\" style=\"color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Life’s sweeter without C &amp; D – Watch Youtube Video</a></p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0;\"><li>Look out for drinks and products which are labelled “Unsweetened”, “Less sugar”, “Reduced sugar”, or “Low in sugar”. However, have them in moderation.</li><li>Don\'t rule out naturally occurring sugars in food such as dried fruits and milk products. However, these will come with other beneficial nutrients like fibre, vitamins or calcium.</li><li>Limit fruit juice. The sugars in unsweetened fruit juice are naturally occurring, but the fibre has been removed from the whole fruit. Because a glass of fruit juice usually contains the juice of several fruits, the amount of sugars and calories add up. Where possible, have fresh whole fruit instead.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1765076400,NULL,0,NULL,NULL,'push'),(68647,'Check food labels for salt ','<html><head></head><body><p><span>Salt is added to many everyday foods, including foods you might not think of as being salty like bread, cakes and biscuits, so always check the label. Some products label sodium instead of salt.</span></p><p><span>Excessive sodium intake increases blood pressure, a major risk factor for stroke and kidney disease. </span></p><p><span>One way to reduce sodium intake is to opt for products carrying the Healthier Choice Symbol (HCS) with this tagline. Such products contain at least 25% less sodium compared to similar products in the same food category. </span></p><p><span>Low sodium doesn\'t mean your food will taste bland. You\'ll find the \"Lower in Sodium\" symbol on flavourful sauces (such as chilli or tomato sauce), recipe mixes and pastes, canned and processed meat and seafood-based products, and ready-to-eat legumes, nuts and seeds. </span><br> <img src=\"https://static.connectedlife.io/assets/images/HCS_Lower_in_Sodium.jpg\" alt=\"Lower in Sodium\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1765681200,NULL,0,NULL,NULL,'push'),(68648,'Look out for \'whole\' in the ingredient list  ','<html><head></head><body><p><span>To identify wholegrain products, look out for the word \"whole\" as in wholemeal, wholegrain or wholewheat on the ingredient list. The wholegrain should ideally be listed as the first or second ingredient. </span></p><p><span>There are also products that are made with some wholegrains, and the word \"whole\" is stated further down the ingredients list. These food may also qualify as a wholegrain food. </span></p><p><span>Another way is to look for products carrying the \"Higher in Wholegrains\" Healthier Choice Symbol, which contain more wholegrains compared to similar products from the same food category. </span></p><img src=\"https://static.connectedlife.io/assets/images/HCS_Higher_in_Wholegrains.jpg\" alt=\"Higher In Wholegrains\" style=\"width: 100%; max-width: 400px; height: 200px;object-fit: contain;\"><p> <a href=\"https://youtu.be/XmbV3VeDjM4?si=0Z4aQd2Wc-QqhPgp\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Go Wholegrain - Watch Youtube Video</a></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1766286000,NULL,0,NULL,NULL,'push'),(68649,'Know your portion size ','<html><head></head><body><p><span>You can find the amount of nutrition per portion on the nutrition information panel. The portion size is recommended by the manufacturer, and can vary between brands.</span></p><p><span>Be aware that the manufacturer\'s portion size might be smaller than yours, which means that even if a product looks healthy, if you have more than this amount, you may still end up consuming more calories, saturated fat, sugar or salt than you realize.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1766890800,NULL,0,NULL,NULL,'push'),(68650,'Let\'s Recap. ','<html><head></head><body><p>Shopping for healthy groceries allows you to cut back on sodium, find wholegrain products, reduce unhealthy oil and fats and limit sugar. One way is to understand food labels.<br><br>In the coming week, which method would you like to try out?</p><ul style=\"margin-top: 0;\"><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1767495600,NULL,0,NULL,NULL,'push'),(68651,'Hey Eloy, did you manage to try out any of these grocery shopping methods?','<html><head></head><body><ul><li>Read the ingredients list</li><li>Check the nutrition information panel</li><li>Be aware of the calorie count</li><li>Find out the type of fat and how much</li><li>Beware of reduced-fat claims</li><li>Spot hidden sugars including naturally occurring sugars</li><li>Look out for \'whole\' in the ingredient list</li><li>Select products with the Healthier Choice Symbol</li><li>Use Nutri-Grade Mark to select healthier beverages</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one method.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1767927600,NULL,0,NULL,NULL,'push'),(68652,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #1 Don\'t shop on an empty stomach</span><br><span>It\'s harder to resist buying higher-fat, higher-calorie snack items when you\'re hungry. Shop after you\'ve eaten a good meal. Drink some water or munch on a fruit before you shop.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1768100400,NULL,0,NULL,NULL,'push'),(68653,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#2 Make a shopping list</span><br><span>Make a shopping list to reduce the urge to buy on impulse. Having a well-planned grocery list also saves time and helps you stick to your healthy eating plan.</span></p><span style=\"color: #FF98B7; font-weight: 500; \">Tips:</span><ul style=\" margin-top: 0;\"><li>Buy only what you will use, not because it is on promotion.</li><li>Resist \"buy one get one\" unless it is a staple.</li><li>Use store apps to compare prices.</li><li>Choose house-brands.</li><li>Select items with longer use-by date.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1768705200,NULL,0,NULL,NULL,'push'),(68654,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#3 Go fresh </span><br>Choose fresh or frozen produce and less processed, wholesome foods (e.g. grains, nuts, eggs, herbs and spices) wherever possible.<br><br>Fresh produce are generally better than processed and ready-to-eat foods so that you know exactly what goes into your meal when you cook at home. They are also lower in fat, sugars and additives.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top:0;\"><li>Spend more time in the fresh produce section.</li><li>Limit your time in the aisles that stock snack food/candy and canned/processed foods.</li><li>Stick reminders on your fridge so that perishable fruit and vegetables are not forgotten in your fridge.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1769310000,NULL,0,NULL,NULL,'push'),(68655,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#4 Frozen or fresh </span><br>Frozen fruits and vegetables are flash-frozen to lock in their nutrients immediately after harvest. Fresh or frozen, fruit and vegetables are nutritious and healthier food choices. <br><br>Frozen produce is easy to keep in the freezer for when needed and will keep for far longer than fresh produce, helping to reduce food waste and save money. For out-of-season items, they can be cheaper than fresh produce.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\"margin-top:0\"><li>Buy enough to ensure everyone in your family have sufficient servings.</li><li>Eat a rainbow. Choose fruit and vegetables of different colours to get the maximum nutrients you need.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1769914800,NULL,0,NULL,NULL,'push'),(68656,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#5 Shop in season. Shop local.</span><br><span>Buy fruits and vegetables in season as they peak in flavour and nutrients, and are cheaper.</span></p><p><span>Most of our fruits and vegetables come from Malaysia, China, USA and Australia while local farms produce 12 percent of our leafy vegetables. Shorter time from source to market means fewer nutrients and flavour are lost in transit.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1770519600,NULL,0,NULL,NULL,'push'),(68657,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> #6 Check food labels </span><br>If you have to buy processed or packaged foods, look out for the Healthier Choice Symbol (HCS). </p><p>The HCS can be found on the packaging of products such as convenience meals, sauces, drinks, snacks and breakfast cereals. Do you recall seeing the HCS on the items you bought recently? </p><p>Use the HCS to compare similar products so that you can choose the healthiest option. </p><p>You can also use the Nutrition Information Panel (NIP) to find out the amount of calories and nutrients you are getting out of each serving of food. <a href=\"https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources\" target=\"_blank\" rel=\"noopener noreferrer\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Learn how to read the NIP at https://www.healthhub.sg/programmes/nutrition-hub/tools-and-resources</a></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1771124400,NULL,0,NULL,NULL,'push'),(68658,'How can I get my money\'s worth of healthy groceries?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">#7 To buy organic produce or not</span><br><span>Numerous studies have been done over the decades but there is no clear conclusion that organic foods are healthier, safer or tastier than conventionally grown ones. Organic or not, make fruit and vegetables a part of your daily diet.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1771729200,NULL,0,NULL,NULL,'push'),(68659,'Let\'s Recap.','<html><head></head><body><p style=\"margin-bottom:0;\">We learned how to get our money\'s worth of healthy groceries.</p><ul style=\"margin-top:0;\"><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p><span>Which would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1772334000,NULL,0,NULL,NULL,'push'),(68660,'Hey Eloy, did you manage to try out any of the dollar stretching ideas?','<html><head></head><body><ul><li>Don\'t shop on an empty stomach</li><li>Make a shopping list</li><li>Buy only what you will use</li><li>Use store apps to compare prices</li><li>Choose fresh/frozen produce and less processed, wholesome foods where possible</li><li>Buy fruit and vegetables in season</li><li>Shop local fruit and vegetables</li><li>Ensure sufficient servings of fruit and vegetables for your family</li><li>Choose fruit and vegetables of different colours</li><li>Check food labels if you\'ve to buy packaged/processed foods</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1772766000,NULL,0,NULL,NULL,'push'),(68661,'Having a well-planned grocery list saves time and helps you stick to your healthy eating plan by making it easier for you to whip up healthier meals for yourself and your family.','<html><head></head><body><p><span>When shopping for healthy groceries, aim for balance, variety, and moderation.</span></p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">More tips:</span></p><ul style=\"padding-left:20px; margin-top:0;\"><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what you have first.</li><li>Then make a grocery list based on your meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to your list throughout the week, whenever you run out of something.</li><li>Buy only what you will use.</li><li>Stock up on pantry staples (e.g. rice, frozen meat/fish/vegetables, canned fish/beans, herbs).</li><li>Shop for perishables (e.g. fruit and vegetables) weekly.</li></ul><p><span>Is there another way to draw up a grocery list?</span></p><p><span>As a matter of fact, yes. But more of that next week.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1772938800,NULL,0,NULL,NULL,'push'),(68662,'Now let\'s get to your question on how to make an efficient grocery list in a few minutes.','<html><head></head><body><p>One way to do this is to organize your grocery list around the store layout. Base your list on how the same types of foods are grouped by aisle.</p><p><span> For Example,</span><br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Rice and Staples</span> aisle: <br>Healthier options include Brown rice, brown rice vermicelli, Whole wheat or whole-grain pasta.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cereals and Breakfast Foods</span> aisle: <br>Healthier options include Whole-grain or multigrain cereals, rolled oats or instant oatmeal, whole-grain cereal bars.</p><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Bakery</span> aisle: <br>Healthier options include Whole wheat bread, pita pockets, Whole-grain flour tortillas.</p><p style=\"margin-bottom:0;\"><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span></p><ul style=\"margin-top:0; padding-left:20px;\"><li>Look for the words \"whole wheat\" or \"whole wheat flour\" as the first ingredient on the label.</li><li>Choose whole-grain breads that contain at least 3 to 4 grams of fiber and have fewer than 100 calories per slice.</li></ul><p>In the weeks to come, I can share more on how to use aisle layout to organise your grocery list.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1773543600,NULL,0,NULL,NULL,'push'),(68663,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Canned Goods</span> aisle:</span><br><span>Healthier options include Diced or whole peeled tomatoes, Beans/lentils/split peas, Tuna or salmon packed in spring water.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Limit consumption of canned foods as they tend to be higher in salt, sugar and fats.</li><li>Select products with the Healthier Choice Symbol.</li><li>When buying canned fruits, choose those that are packed in juice rather than syrup.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1774148400,NULL,0,NULL,NULL,'push'),(68664,'Organising grocery list by aisle','<html><head></head><body><p><em><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Cooking Oils</span> aisle:</em><br><span>Healthier options include Canola oil, olive oil, peanut oil, rice bran oil, soybean oil, sesame oil.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><ul style=\" margin-top: 0;\"><li>Cooking oils have different smoke points.</li><li>For high-heat cooking (e.g. stir/deep frying), choose oils with higher smoke point such as peanut/rice bran/soybean oil.</li><li>Extra virgin olive oil has a relatively low smoke point of 199 °C and is not suitable for high-heat cooking.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1774753200,NULL,0,NULL,NULL,'push'),(68665,'Organising grocery list by aisle','<html><head></head><body><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Sauces and Condiments</span> aisle:</span><br><span>Many sauces, salad dressings and condiments are high in sodium, sugar and saturated fat.</span></p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>Opt for products that carry the \"Lower in Sodium\", \"Lower in Sugar\" or \"Lower in Saturated Fat\" Healthier Choice Symbol.</span><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Snacks and Crackers</span> aisle:</span><br><span>Healthier options include Whole-grain crackers, Dried fruit, nuts and seeds, peanut butter or almond butter, hummus, dark chocolates.</span></p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Drinks</span> aisle:</span><br><span>Healthier options include Unsweetened green and flavoured teas, Sparkling water.</span></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1775358000,NULL,0,NULL,NULL,'push'),(68666,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dairy and Eggs</span> aisle:<br>Healthier options include Skim or low-fat milk or soymilk, Fat-free or low-fat plain yogurt, Low-fat cheese, Eggs, Tofu, Butter or spread (a variety that doesn\'t contain hydrogenated oils).<br> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Meat and Seafood</span> aisle:<br>Healthier options include Skinless chicken breast, minced chicken, salmon, seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tip:</span><br><span>If you buy red meat, choose the leanest cuts.</span><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Frozen Food</span> aisle:<br>Healthier options include Frozen fruit and vegetables, frozen meat/poultry/seafood.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Use frozen vegetables to prepare soups, casseroles, and stews.</li><li>Low-fat frozen plain yogurt blended with frozen fruit makes a quick, healthy smoothie.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1775962800,NULL,0,NULL,NULL,'push'),(68667,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1776567600,NULL,0,NULL,NULL,'push'),(68668,'Let\'s Recap','<html><head></head><body><p><span>Having a well-planned grocery list saves time and helps you stick to your healthy eating plan.</span><br><br><span>Next time you go grocery shopping, which tips would you like to try out?</span></p><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1777172400,NULL,0,NULL,NULL,'push'),(68669,'Hey Eloy, did you manage to try out any of the grocery shopping tips?','<html><head></head><body><ul style=\" margin-top: 0;\"><li>Organise my grocery list around the store aisle layout.</li><li>Plan how many meals to cook for the week.</li><li>Check freezer and pantry for what I have first.</li><li>Then make a grocery list based on my meal plan.</li><li>Schedule a day and time for grocery shopping.</li><li>Add food to my list whenever I run out of something.</li><li>Buy only what I will use.</li><li>Stock up on pantry staples.</li><li>Shop for perishables weekly.</li></ul><p>If you have tried, how was your experience?<br>If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1777604400,NULL,0,NULL,NULL,'push'),(68670,'Organising grocery list by aisle','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Fresh Fruit and Vegetables</span> aisle:</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\" margin-top: 0;\"><li>Include a variety of colourful fruits and vegetables to get the range of nutrients your body needs.</li><li>Buy local fruits and vegetables that are in season as they taste better and cost less.</li><li>Always shop for fresh and frozen produce last.</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1777777200,NULL,0,NULL,NULL,'push'),(68671,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Tropical Fruits</span><br>Choose <strong>mangosteens</strong> that can be pressed in slightly.<br><strong>Mangoes</strong> should be slightly soft with an intense fragrance.<br><strong>Dragonfruits</strong> are evenly pink with fresh-looking petals and a soft stem.<br>Pick yellow <strong>papayas</strong> that are slightly soft when pressed and is heavy for its size.<br>Ripe <strong>pineapples</strong> are yellow with a pleasant aroma at the stem end.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1778382000,NULL,0,NULL,NULL,'push'),(68672,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Citrus Fruits</span><br>Choose <strong>citrus fruits</strong> that are firm, bright-looking with finely-textured peel and give off a strong fragrance.<br>Choose <strong>grapefruits</strong> that are redder and pomelos with a yellow tinge.<br>Choose navel <strong>oranges</strong> if you like them to be sweet and seedless.<br><strong>Kiwis</strong> are slightly soft when ripe and have taut skin.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1778986800,NULL,0,NULL,NULL,'push'),(68673,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Melons</span><br>Ripe <strong>watermelons</strong> look dull, not shiny and have dried stem ends. Look for the cream-coloured patch on the skin where they rested on the ground before harvest — the deeper the colour, the better it is.<br>Netted melons such as <strong>rockmelons and cantaloupes</strong> give off an intense fragrance when they are fully ripe. <br>Baby-skinned <strong>honeydew</strong> does not wear a scent when they are ripe. Instead, look for a yellow tinge in their waxy exterior. The stem end of <strong>all melons</strong> can be pressed in gently when they are ripe.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1779591600,NULL,0,NULL,NULL,'push'),(68674,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Berries</span><br>Choose <strong>blueberries</strong> that are plump, brightly-coloured with a whitish bloom. Shake the container of blueberries gently. If the berries don’t move freely, they may be soft or damaged.<br>Buy <strong>strawberries</strong> that give off a strong scent, an indication that they are sweet and ripe.<br>Look for shiny and firm <strong>blackberries</strong>.<br><strong>Raspberries</strong> should be firm, plump and deeply-coloured.</p><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"  margin-top: 0;\"><li>Store blackberries and raspberries in a single layer as they bruise easily</li><li>Berries only stay fresh for a few days, so eat them fast! If not, freeze them for frozen sweet treats</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1780196400,NULL,0,NULL,NULL,'push'),(68675,'How to pick fresh fruits?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Stone fruits (e.g. plum, peach, nectarine, apricot)</span><br><span>Select <strong>stone fruits</strong> with firm skin that is not wrinkled. Softer fruits are sweeter and juicier. Leave them to ripen before storing them in the fridge. A deeper colour is a hint of ripeness, especially around the stem end.</span></p><p><span><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Other fruits</span></span><br><span><strong>Apples</strong> and <strong>pears</strong> should be firm and smooth-skinned.</span><br><span>A ripe <strong>passionfruit</strong> is plump, heavy for its size and wrinkled.</span><br><span>Look for plump <strong>grapes</strong> with a whitish bloom and healthier brown stems that still hold the fruit firmly.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1780801200,NULL,0,NULL,NULL,'push'),(68676,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Dark green vegetables</span><br><strong>Leafy vegetables</strong> such as spinach should have bright green leaves and tender, crisp stems.<br>Fresh <strong>broccolis</strong> have compact, green florets and undamaged stems.<br><strong>Lettuce</strong> leaves should be crisp and bright.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1781406000,NULL,0,NULL,NULL,'push'),(68677,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Red and orange vegetables</span><br><span>Pick slim, medium-sized <strong>carrots</strong> which are well-formed and bright.</span><br><span><strong>Capsicums</strong> and <strong>chilli</strong> should be firm, deeply-coloured and glossy.</span><br><span>Avoid <strong>sweet potatoes</strong> with stringed “beards” as they are older and less tasty! Pick small to medium-sized ones with even tones.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1782010800,NULL,0,NULL,NULL,'push'),(68678,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Beans and peas</span><br>Edible bean pods such as <strong>French beans, green beans and snow peas</strong> taste better when they are tender and crisp with smaller beans within them<br><strong>Sweet peas</strong> are firm and crisp; they should not bend<br><strong>Dried beans</strong> should be free from mould, insects or discolouration</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1782615600,NULL,0,NULL,NULL,'push'),(68679,'How to choose fresh vegetables?','<html><head></head><body><p><strong><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Starchy vegetables</span></strong><br>Choose <strong>potatoes</strong> which are firm and have fewer “eyes”. They should not have any sprouts.<br>Look for bright and plump <strong>corn</strong> kernels when buying an ear of corn.<br>A lighter <strong>yam</strong> (or taro) is a better pick as it has less water and more likely to be “powdery”. When choosing yam that has been cut, look for the ones with more red veins inside.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1783220400,NULL,0,NULL,NULL,'push'),(68680,'How to choose fresh vegetables?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Others</span><br><span>A good <strong>cabbage</strong> should be firm or even hard.</span><br><span>Tender <strong>asparagus</strong> are bright green with tightly closed spears that have darker green or purplish tips.</span><br><span><strong>Cauliflower</strong> heads should be firm and compact with no brown spots.</span><br><span>If you are buying the longer variety of <strong>eggplant</strong> (or brinjal), hold it up and test if it is springy (and young) by flicking it gently.</span><br><span>Smaller and shorter <strong>lady’s fingers</strong> are younger and crisper.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1783825200,NULL,0,NULL,NULL,'push'),(68681,'Let\'s Recap.','<html><head></head><body><p><span>Thinking of your favourite fruit and vegetables, which method/s would you like to try out in the coming week?</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1784430000,NULL,0,NULL,NULL,'push'),(68682,'Hey Eloy, did you manage to use any of the ideas to pick your favourite fruit and vegetables?','<html><head></head><body><p><span>If you have tried, how was your experience? <br>If not, you still have time to try at least one action. You can revisit the tips in the Notification Centre.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1784862000,NULL,0,NULL,NULL,'push'),(68683,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><span>Eating out is both fun and sociable. But it is easy to wind up overeating or indulging in a lot more fat, sugar, and salt than you normally would if you ate at home. In the weeks to come, I can share with you some clever tips to help you eat healthy at restaurants.</span></div><p style=\"margin-top:0px;margin-bottom:0px;\"><strong><em>Guide to healthy dining at restaurant</em></strong> <br><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Plan ahead</span> <br><span>If you plan to eat out at your favourite restaurant, eat lighter meals through the rest of the day to allow for the additional calories you may indulge in.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1756868400,NULL,0,NULL,NULL,'push'),(68684,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Be the first</em><br><span>Be the first to recommend a restaurant that serves healthier options or the first in your group to order a healthy dish. </span></div><div style=\"margin-bottom:20px;\"><span style=\" color: #FF98B7; font-style: italic; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\"><a href=\"https://www.healthhub.sg/live-healthy/5-healthier-cbd-lunchtime-dining-options\" style=\"color: #FF98B7; font-weight: 500; font-style: italic; text-decoration: underline; text-decoration-color: #FF98B7;\"> Which of your favourite restaurants offer healthier options? </a> </span></div><p style=\"margin-bottom:0px; margin-top:0px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Read the menu before you go</span><br><span>Choose your food before you get to the restaurant. It\'s easy to make unhealthy choices when hungry. The sight and smell of food and the food choices that others make can easily distract you from sticking to your health goals.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1757473200,NULL,0,NULL,NULL,'push'),(68685,'Guide to healthy dining at restaurant','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Choose dishes prepared using healthier methods </em><br><span>Avoid or limit items with names like crispy, deep-fried, in cream sauce, lemak, with coconut milk or in syrup as these tend to be higher in sugar and fat. </span></p><p><span>Ask the waiter or staff if you do not understand the fancy names of dishes. Dishes that are steamed, grilled, roasted or pan-fried are generally lower in calories. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1758078000,NULL,0,NULL,NULL,'push'),(68686,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom:20px;\"><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order just enough</em><br><span>To control how much you eat, order just enough. You can always top up the food order later if needed. </span></div><div style=\"margin-bottom:20px;\"><span>Consider sharing food with someone else or ordering a half-portion if available. If you are going to a restaurant where you know the portions are huge, try ordering two appetizers instead of one main course. </span></div><p style=\"margin-top: 0px; margin-bottom:0px;\"><span>If there are extras, ask the waiter to bag it up if you do not like to see food wasted. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1758682800,NULL,0,NULL,NULL,'push'),(68687,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Order a variety of dishes</span><br><span>Select a variety of items to make up a well-balanced meal. Include a staple, one or two vegetable side dishes, and one or two protein-rich items such as tofu, lentils, fish, chicken or lean meat. </span></div><div style=\"margin-bottom: 20px;\"><span>Consider starting with a salad, which not only adds greens to your meal but can also help to control your appetite. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Keep deep-fried or oily and fatty dishes to no more than one or two per meal. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1759287600,NULL,0,NULL,NULL,'push'),(68688,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Request for modifications </span><br><span>Don\'t be afraid to ask for modifications to your food.</span></div><div style=\"margin-bottom: 20px;\"><span>When placing your order, ask for your dishes to be prepared with less oil and sodium-containing seasonings. </span></div><p style=\"margin-bottom: 0px; margin-top:0px;\"><span>Considering swapping part of your meal, such as fries or potatoes, for extra vegetables or a salad. This can boost your fibre intake and reduce your calories consumed. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1759892400,NULL,0,NULL,NULL,'push'),(68689,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\"> Ask for sauces or dressings on the side </span><br> Sauces and dressings can be a hidden source of sugar, sodium and fat. Ask for sauces and dressings to be on the side so you can decide on the amount to add. </div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><a href=\"https://youtu.be/GXSO2-X4Cx4?si=w8JzuKUbLgvDTj0C\" rel=\"noopener noreferrer\" target=\"_blank\" style=\" color: #FF98B7; font-weight: 500; text-decoration: underline; text-decoration-color: #FF98B7;\">Take less sauces and gravy - Watch Youtube Video</a></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1760497200,NULL,0,NULL,NULL,'push'),(68690,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span <span=\"\" style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Limit sugar-sweetened beverages and alcohol</span><br><span>For drinks, nothing beats water. Drinking water instead of sugar-sweetened drinks can help reduce your intake of calories and added sugar.</span></div><div style=\"margin-bottom: 20px;\"><span>If you would still like a beverage, opt for no-sugar or reduced-sugar drinks. For example, instead of a flavoured latte, go for a long black or a regular latte. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>Alcoholic beverages are often high in calories with little nutritional value. If you must have a drink, limit yourself to 1 standard drink and opt for lower-calorie options like light beer and wine spritzers instead of sugary cocktails or mixed drinks. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1761102000,NULL,0,NULL,NULL,'push'),(68691,'Guide to healthy dining at restaurant','<html><head></head><body><div style=\"margin-bottom: 20px;\"><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">End the meal with fresh fruits instead of desserts</span><br><span>Craving a sweet treat at the end of your meal? Opt for a fresh fruit platter! It is a naturally sweet option that packs plenty of essential vitamins and minerals. </span></div><p style=\"margin-bottom: 0px; margin-top: 0px;\"><span>If you still want to enjoy other desserts, select one with less sugar or syrup and cream. </span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1761706800,NULL,0,NULL,NULL,'push'),(68692,'Guide to healthy dining at restaurant','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Enjoy your favourite food in moderation</span><br><span>There will be times when you want to eat your favourite food and not worry about whether it is healthy or not. If you\'ve been eating healthily most of the time, go ahead and enjoy an occasional treat. Being flexible about your diet and food choices is linked with better overall health and weight management.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1762311600,NULL,0,NULL,NULL,'push'),(68693,'How do I avoid overeating when dining out?','<html><head></head><body><p><em style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat mindfully</em><br><span>Slow down to give your body enough time to tell you that you are feeling full. Chew thoroughly and take the time to savour the aromas and flavours of your meal. Stop eating when you feel three-quarter full.</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1762916400,NULL,0,NULL,NULL,'push'),(68694,'What can I do to eat healthy at a fast-food restaurant?','<html><head></head><body><p><span>Fast food is convenient but tends to be high in calories, salt and fat. When consumed frequently and in excess, it may raise your risk of obesity, heart attack and other health issues.</span></p><div><span style=\"color: #FF98B7; font-weight: 500;\">Tips:</span><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Resist upsizing the meal and drinks even though it may seem to make more monetary sense.</li><li>Select items that are grilled, not fried</li><li>Swap deep-fried sides (e.g. french fries or chips) for salad or steamed corn</li><li>If craving a sweet treat, opt for a cup of fresh fruits instead of ice-cream, sundae, or apple pie</li><li>Swap soft drinks for water</li><li>Ask for more vegetables in your burger</li></ul></div></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1763521200,NULL,0,NULL,NULL,'push'),(68695,'How do I control myself when dining at all-you-can-eat buffet?','<html><head></head><body><p><span style=\"color: #5dacf3; font-style: italic; font-weight: 500;\">Eat just enough </span><br><span>If you find yourself at all-you-can-eat buffet, select one favourite item from each section of the buffet line and eat no more than your regular portion. </span></p><p><span>Help yourself to small servings if you want to try the entire spread.</span></p><p><span>Eat slowly and take the time to savour your meal. Stop eating when you feel three-quarters full</span></p><p><span>If you are under pressure to keep eating to support your friends, eat slowly and steer the conversation away from your plate.</span></p><p><span>Spend more time socialising than eating</span></p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1764126000,NULL,0,NULL,NULL,'push'),(68696,'Choose one action to try out the next time you dine at a restaurant:','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1764730800,NULL,0,NULL,NULL,'push'),(68697,'Hey Eloy, did you manage to try out any of these healthy dining tips? ','<html><head></head><body><ul style=\"margin-top: 0; padding-left: 20px;\"><li>Eat lighter meals throughout the day</li><li>Be the first to recommend a restaurant that serves healthier options</li><li>Read the menu before you go</li><li>Order just enough</li><li>Choose dishes prepared using healthier methods</li><li>Order a variety of dishes</li><li>Request for modifications</li><li>Ask for sauces or dressings on the side</li><li>Limit sugar-sweetened beverages and alcohol</li><li>End the meal with fresh fruits instead of desserts</li><li>Slow down and chew thoroughly</li><li>Stop eating when you feel three-quarters full</li><li>Help yourself to small servings</li></ul><p>If you have tried, how was your experience? If not, you still have time to try at least one action.</p></body></html>','pending','2025-08-27 05:41:46','2025-08-27 05:41:46',0,8318291,0,0,1765162800,NULL,0,NULL,NULL,'push');
/*!40000 ALTER TABLE `notifications_scheduled` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `nw_equipment`
--

DROP TABLE IF EXISTS `nw_equipment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `nw_equipment` (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `isActive` tinyint NOT NULL DEFAULT '1',
  `createdAt` int NOT NULL,
  `updatedAt` int DEFAULT NULL,
  `adminType` text,
  `deletedAt` datetime(6) DEFAULT NULL,
  `createdByUserId` int DEFAULT NULL,
