INSERT INTO `nw_exercise` VALUES (131,'Walking (For Stride Analysis)','walking','Stand tall and look forwards. Hold the wall only if you need to. Step forwards and walk for few minutes.',NULL,1,1753682764,1753682764,NULL,NULL,NULL),(132,'Sit to Stand Test','sit_to_stand','1. Sit on the chair with your feet flat on the floor.\n        2. when you start the timer, stand up and sit down as many as you can until the timer finishs.\n        3. Record how many times you are able to stand up.',NULL,1,1753682764,1753682764,NULL,NULL,NULL);
