INSERT INTO `preprogram_survey_questions` VALUES (45,'How satisfied are you with the learning experience from HealthTrack SG on how to improve your lifestyle?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20',12,NULL,NULL,NULL,'Please rate on a score of 1 to 10 (1 being Very Dissatisfied and 10 being Very Satisfied)','1 = “Very Dissatisfied”','10 = “Very Satisfied”','Q1'),(46,'As a result of HealthTrack SG how confident do you now feel about improving your lifestyle?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20',12,NULL,NULL,NULL,'Please rate on a score of 1 to 10 (1 being Not Confident At All and 10 being Very Confident)','1 = “Not Confident At All”','10 = “Very Confident”','Q2'),(47,'How likely are you to recommend HealthTrack SG to a colleague, friend or family member?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20',12,NULL,NULL,NULL,'Please rate on a score of 1 to 10 (1 being Very Unlikely and 10 being Very Likely)','1 = “Very Unlikely”','10 = “Very Likely”','Q3'),(48,'How well does the HealthTrack SG app meet your needs?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20',14,NULL,NULL,NULL,'Please rate on a score of 1 to 10 (1 being Not Well At All and 10 being Extremely Well)','1 = “Not Well At All”','10 = “Extremely Well”','Q4'),(49,'How easy is it to navigate the HealthTrack SG app?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20',14,NULL,NULL,NULL,'Please rate on a score of 1 to 10 (1 being Very Hard and 10 being Very Easy)','1 = “Very Hard”','10 = “Very Easy”','Q5'),(50,'How much effort did you have to put in to use the HealthTrack SG app?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20',14,NULL,NULL,NULL,'Please rate on a score of 1 to 10 (1 being A Lot Of Effort and 10 being Very Little Effort)','1 = “A Lot Of Effort”','10 = “Very Little Effort”','Q6'),(51,'How did this effort compare with your expectations at the start of the programme?','matrix',1,10,'2025-07-28 04:46:20','2025-07-28 04:46:20'